// Comprehensive finance vocabulary — broad coverage for search.
// Each entry is a "fiche": a real explanation, with French aliases so the
// search finds terms whether the user types English or French.
// `conceptId` links the term to a deep concept page when one exists.
//
// Categories mirror the main `categories` array in concepts.js, plus
// 'fintech' and 'accounting' for crypto and financial-statement terms.

export const glossary = [
  /* ---------------- FOUNDATIONS ---------------- */
  { term: 'Time Value of Money', aliases: ['valeur temporelle de l\'argent', 'valeur temps de l\'argent', 'tvm', 'valeur actuelle', 'present value', 'valeur future', 'future value'], category: 'foundations', conceptId: 'time-value-of-money', def: 'The principle that a sum of money today is worth more than the same sum later, because money in hand can be invested and grow. Every loan, bond, and retirement calculation is built on this discounting/compounding math.' },
  { term: 'Compound Interest', aliases: ['intérêts composés', 'composition', 'capitalisation des intérêts', 'interest on interest'], category: 'foundations', conceptId: 'compound-interest', def: 'Earning a return on both your original money and the interest it has already accumulated, so growth accelerates over time. The "eighth wonder" — returns that earn their own returns.' },
  { term: 'Inflation', aliases: ['inflation', 'hausse des prix', 'pouvoir d\'achat', 'purchasing power'], category: 'foundations', conceptId: 'inflation', def: 'A sustained rise in the general price level, meaning each unit of currency buys less over time. Low predictable inflation (~2%) is healthy; high inflation erodes savings and distorts planning.' },
  { term: 'Deflation', aliases: ['déflation', 'baisse des prix'], category: 'foundations', conceptId: 'inflation', def: 'A sustained fall in the general price level — the opposite of inflation. It rewards not spending, which can stall an economy and make debts harder to repay.' },
  { term: 'Stagflation', aliases: ['stagflation'], category: 'economics', conceptId: 'inflation', def: 'The ugly combination of stagnant growth, high unemployment, and high inflation at once — which classic policy tools struggle to fix because fighting one worsens another.' },
  { term: 'Disinflation', aliases: ['désinflation'], category: 'economics', conceptId: 'inflation', def: 'A slowdown in the rate of inflation (prices still rising, but more slowly) — not to be confused with deflation, where prices actually fall.' },
  { term: 'Real Return', aliases: ['rendement réel', 'taux réel', 'real rate', 'rendement ajusté de l\'inflation'], category: 'foundations', conceptId: 'inflation', def: 'The return on an investment after subtracting inflation — what your money actually gained in purchasing power. A 5% nominal return at 4% inflation is only a 1% real return.' },
  { term: 'Nominal Return', aliases: ['rendement nominal', 'taux nominal'], category: 'foundations', conceptId: 'inflation', def: 'The stated return on an investment, not adjusted for inflation. A savings account paying 3% when inflation is 4% is losing money in real terms.' },
  { term: 'Risk vs. Return', aliases: ['risque rendement', 'couple risque rendement', 'risk return tradeoff', 'prime de risque', 'risk premium'], category: 'foundations', conceptId: 'risk-vs-return', def: 'The inescapable pairing: higher potential returns always come with higher risk of loss. There is no free lunch — a high "guaranteed" return is hiding risk somewhere.' },
  { term: 'Risk Premium', aliases: ['prime de risque', 'prime de risque action', 'equity risk premium'], category: 'foundations', conceptId: 'risk-vs-return', def: 'The extra return investors demand for taking risk above the risk-free rate. The equity risk premium is the extra pay stocks offer over government bonds, compensation for living through crashes.' },
  { term: 'Risk-Free Rate', aliases: ['taux sans risque', 'taux de l\'argent sans risque'], category: 'foundations', conceptId: 'risk-vs-return', def: 'The return on the safest available asset, usually short-term government debt. It is the baseline every other return is measured against — all other assets add a risk premium on top.' },
  { term: 'Opportunity Cost', aliases: ['coût d\'opportunité', 'coût de renonciation'], category: 'foundations', conceptId: 'opportunity-cost', def: 'The value of the next-best alternative you give up when you make a choice. The true cost of anything includes what the money would have earned instead — the invisible price tag.' },
  { term: 'Sunk Cost', aliases: ['coût irrécupérable', 'sunk cost fallacy', 'frais engagés'], category: 'foundations', conceptId: 'opportunity-cost', def: 'Money already spent that should not affect future decisions. Holding a losing investment "until it comes back" is the sunk-cost fallacy — the money is gone regardless of what you do now.' },
  { term: 'Discount Rate', aliases: ['taux d\'actualisation', 'taux d\'escompte'], category: 'foundations', conceptId: 'time-value-of-money', def: 'The rate used to bring future cash flows back to today\'s value. Small changes in the discount rate swing valuations enormously over long horizons.' },
  { term: 'Rule of 72', aliases: ['règle de 72', 'règle des 72'], category: 'foundations', conceptId: 'compound-interest', def: 'A shortcut: divide 72 by the annual rate to estimate how many years it takes money to double. At 6%, money doubles in roughly 12 years.' },
  { term: 'Effective Annual Rate', aliases: ['taux annuel effectif', 'ear', 'taux équivalent annuel', 'apy'], category: 'banking', conceptId: 'interest-rate', def: 'The true yearly rate after accounting for compounding. A 6% nominal rate compounded monthly is really 6.17% effective — always compare EAR to EAR.' },

  /* ---------------- INVESTING ---------------- */
  { term: 'Diversification', aliases: ['diversification', 'répartition des risques'], category: 'investing', conceptId: 'diversification', def: 'Spreading money across many unrelated assets so no single failure can sink you, while keeping overall return. The closest thing to a free lunch in finance — risk falls sharply for little return given up.' },
  { term: 'Correlation', aliases: ['corrélation', 'corrélé'], category: 'investing', conceptId: 'diversification', def: 'How closely two assets\' returns move together, from −1 (opposite) to +1 (identical). Low correlation is the engine of diversification — 30 banks are not diversified.' },
  { term: 'Systematic Risk', aliases: ['risque systématique', 'risque de marché', 'market risk', 'non-diversifiable risk'], category: 'investing', conceptId: 'diversification', def: 'Market-wide risk that diversification cannot remove — recessions, wars, rate shocks affect everything. You are paid a risk premium for bearing it; you cannot diversify it away.' },
  { term: 'Unsystematic Risk', aliases: ['risque spécifique', 'risque non systématique', 'risque idiosyncratique', 'specific risk'], category: 'investing', conceptId: 'diversification', def: 'Risk tied to a single company or sector — a lawsuit, a factory fire, a product failure. Diversification removes most of it; that is why you diversify.' },
  { term: 'Dollar-Cost Averaging', aliases: ['dca', 'investissement périodique', 'achats échelonnés', 'lissage de coût', 'investissement automatique'], category: 'investing', conceptId: 'dollar-cost-averaging', def: 'Investing a fixed amount on a fixed schedule regardless of price, so you buy more shares when cheap and fewer when dear. Its real power is behavioral — it removes "is now a good time?"' },
  { term: 'Lump-Sum Investing', aliases: ['investissement en bloc', 'placement global'], category: 'investing', conceptId: 'dollar-cost-averaging', def: 'Investing everything at once rather than gradually. Beats DCA on average (markets rise over time), but DCA reduces regret and timing risk.' },
  { term: 'ETF', aliases: ['etf', 'tracker', 'fonds coté', 'exchange traded fund'], category: 'investing', conceptId: 'etf', def: 'A fund that tracks an index and trades on an exchange like a stock, with very low fees. One purchase can hold thousands of companies for a few basis points a year.' },
  { term: 'Index Fund', aliases: ['fonds indiciel', 'fonds indiciels', 'gestion passive', 'fonds de réplication'], category: 'investing', conceptId: 'etf', def: 'A fund that replicates a market index rather than picking stocks, charging tiny fees. After costs, low-cost index funds beat the large majority of active managers over long periods.' },
  { term: 'Expense Ratio', aliases: ['ter', 'total expense ratio', 'frais de gestion', 'ratio de frais'], category: 'investing', conceptId: 'etf', def: 'The yearly fee a fund charges as a percentage of assets. A 0.9% fee difference compounds into a six-figure gap over 30 years — fees are the only reliable predictor of long-term returns.' },
  { term: 'Active Management', aliases: ['gestion active', 'fonds actifs'], category: 'investing', conceptId: 'etf', def: 'A manager picks securities trying to beat a benchmark. Usually fails after fees; the few who win are hard to identify in advance and rarely repeat.' },
  { term: 'Passive Management', aliases: ['gestion passive', 'indexation'], category: 'investing', conceptId: 'etf', def: 'Replicating an index at minimal cost rather than picking stocks. Concedes the unwinnable stock-picking game to win the winnable cost-and-discipline game.' },
  { term: 'Dividend', aliases: ['dividende', 'coupon dividende'], category: 'investing', conceptId: 'dividends', def: 'A share of company profit paid to shareholders, usually quarterly, in cash. Mature profitable companies pay them; fast-growers reinvest instead.' },
  { term: 'Dividend Yield', aliases: ['rendement dividende', 'taux de distribution', 'dividend yield'], category: 'investing', conceptId: 'dividends', def: 'The annual dividend divided by the share price — the cash return. A €100 stock paying €3/year has a 3% yield. High yield can signal risk, not a bargain.' },
  { term: 'Dividend Aristocrat', aliases: ['aristocrate du dividende', 'dividend aristocrat'], category: 'investing', conceptId: 'dividends', def: 'A company that has raised its dividend for 25+ years — a signal of durable, growing profits. Prized for steady income and inflation protection.' },
  { term: 'Buyback', aliases: ['rachat d\'actions', 'share repurchase', 'buyback', 'rachat de titres'], category: 'investing', conceptId: 'dividends', def: 'A company buying back its own shares, shrinking the count and lifting per-share value. Like a dividend but more tax-efficient and flexible; smart when stock is cheap, value-destroying when overpriced.' },
  { term: 'Capital Gain', aliases: ['plus-value', 'gain en capital', 'capital gain', 'plus value'], category: 'investing', conceptId: 'dividends', def: 'The profit from selling an asset for more than you paid. Taxed differently (often more favorably) than dividends or interest in many countries.' },
  { term: 'Rebalancing', aliases: ['rééquilibrage', 'réajustement de portefeuille'], category: 'investing', conceptId: 'risk-management', def: 'Periodically selling winners and buying losers to return a portfolio to its target mix. Forces you to buy low and sell high, and keeps risk at your intended level.' },
  { term: 'Asset Allocation', aliases: ['allocation d\'actifs', 'répartition d\'actifs'], category: 'investing', conceptId: 'risk-vs-return', def: 'How you split a portfolio across asset classes (stocks, bonds, cash, real estate). It explains most of a portfolio\'s risk and return — far more than which specific securities you pick.' },
  { term: 'Value Investing', aliases: ['investissement value', 'investissement dans la valeur', 'value stocks'], category: 'investing', def: 'Buying shares that look cheap relative to their fundamentals (earnings, book value, cash flow). Bet: the market is wrong and will eventually reprice them upward.' },
  { term: 'Growth Investing', aliases: ['investissement growth', 'croissance', 'growth stocks'], category: 'investing', def: 'Buying shares of companies growing faster than the market, even at high valuations. Bet: growth continues long enough to justify the price.' },
  { term: 'Factor Investing', aliases: ['investissement factoriel', 'smart beta', 'facteurs'], category: 'investing', def: 'Tilting a portfolio toward proven return drivers — value, size, momentum, quality, low volatility. A middle ground between active stock-picking and pure indexing.' },
  { term: 'Momentum', aliases: ['momentum', 'inertie de cours', 'tendance'], category: 'investing', def: 'The tendency for assets that have risen to keep rising (and vice versa) for a while. A robust empirical effect, though it reverses violently when it ends.' },
  { term: 'DRIP', aliases: ['drip', 'réinvestissement des dividendes', 'dividend reinvestment plan'], category: 'investing', conceptId: 'dividends', def: 'A plan that automatically uses dividends to buy more shares, commission-free. The compounding engine for income portfolios — dividends buy dividends.' },
  { term: 'Portfolio', aliases: ['portefeuille'], category: 'investing', def: 'The full collection of investments a person or institution owns. Its risk/return is driven mostly by the mix of asset classes, not the individual holdings.' },
  { term: 'Modern Portfolio Theory', aliases: ['mpt', 'théorie moderne du portefeuille', 'frontière efficiente', 'efficient frontier'], category: 'investing', conceptId: 'portfolio-theory', def: 'Markowitz\'s framework showing how to combine assets to maximize return for a given risk. The birth of the "efficient frontier" — the set of optimal portfolios no other combination can beat.' },
  { term: 'Efficient Frontier', aliases: ['frontière efficiente', 'frontière d\'efficience'], category: 'investing', conceptId: 'portfolio-theory', def: 'The curve of portfolios offering the highest return for each level of risk. Rational investors hold a portfolio on this line; anything below it is dominated.' },
  { term: 'Sharpe Ratio', aliases: ['ratio de sharpe', 'sharpe', 'ratio rendement/risque'], category: 'investing', conceptId: 'sharpe-ratio', def: 'Return per unit of risk: (return − risk-free rate) ÷ volatility. The standard way to compare investments or managers on a risk-adjusted basis — higher is better.' },
  { term: 'Beta', aliases: ['bêta', 'beta', 'coefficient bêta'], category: 'investing', conceptId: 'beta', def: 'How much an asset moves with the market: beta 1 = market-like, 2 = double the swings, 0.5 = half. High-beta stocks amplify the market both up and down.' },
  { term: 'Alpha', aliases: ['alpha', 'valeur ajoutée du gérant'], category: 'investing', conceptId: 'asset-manager', def: 'Return above what an asset\'s risk (beta) would justify — the manager\'s genuine skill, or luck. Persistent alpha after fees is extremely rare.' },
  { term: 'CAPM', aliases: ['medaf', 'modèle d\'évaluation des actifs financiers', 'capm', 'capital asset pricing model'], category: 'investing', conceptId: 'capm', def: 'A model linking expected return to risk: expected return = risk-free rate + beta × market premium. The simplest theory of how risk should be priced.' },
  { term: 'Efficient Market Hypothesis', aliases: ['emh', 'efficience des marchés', 'hypothèse d\'efficience', 'marché efficient'], category: 'investing', conceptId: 'efficient-market', def: 'The theory that prices already reflect all available information, so you cannot systematically beat the market. Roughly true, which is why active management rarely wins after fees.' },
  { term: 'Volatility', aliases: ['volatilité', 'vol', 'amplitude de variation'], category: 'risk', conceptId: 'volatility', def: 'How much an asset\'s price swings around its average — the usual proxy for risk. Higher volatility means wider possible outcomes, both up and down.' },
  { term: 'Drawdown', aliases: ['drawdown', 'plus forte baisse', 'creux'], category: 'risk', conceptId: 'bull-bear-market', def: 'The drop from a past peak to the subsequent trough. A 50% drawdown needs a 100% gain to recover — losses are asymmetric, which is why avoiding catastrophic drawdowns matters.' },
  { term: 'Maximum Drawdown', aliases: ['drawdown maximal', 'perte maximale', 'max drawdown'], category: 'risk', def: 'The worst peak-to-trough decline a portfolio ever experienced. The real measure of pain — what an investor actually had to endure, not the average volatility.' },
  { term: 'Value at Risk', aliases: ['var', 'valeur en risque', 'value at risk'], category: 'risk', def: 'The maximum loss expected over a set horizon at a given confidence level — e.g. "€1M 1-day 99% VaR" means a loss over €1M in one day, 1% of the time. A standard but flawed risk metric (it says nothing about the tail beyond it).' },
  { term: 'Tail Risk', aliases: ['risque de queue', 'événement extrême', 'tail risk', 'black swan'], category: 'risk', conceptId: 'risk-management', def: 'Low-probability, high-impact events in the far tail of the distribution. These "black swans" dominate long-term outcomes — and are exactly what insurance and hedging exist for.' },
  { term: 'Black Swan', aliases: ['cygne noir', 'black swan event'], category: 'risk', def: 'A rare, unpredictable, high-impact event (Taleb\'s term). By definition not foreseeable from past data — the case for robustness over optimization in risk management.' },
  { term: 'Stress Test', aliases: ['test de résistance', 'stress testing', 'scénario de crise'], category: 'risk', def: 'Simulating extreme scenarios to see what survives. Asks "what breaks?" rather than "what usually happens?" — the discipline behind bank capital and prudent portfolio construction.' },

  /* ---------------- MARKETS ---------------- */
  { term: 'Market Capitalization', aliases: ['capitalisation boursière', 'cap', 'market cap', 'valeur de marché'], category: 'markets', conceptId: 'market-cap', def: 'The stock market\'s valuation of a whole company: share price × shares outstanding. The real yardstick for company size — share price alone says nothing.' },
  { term: 'Large-Cap', aliases: ['large cap', 'grande capitalisation', 'big cap', 'blue chip'], category: 'markets', conceptId: 'market-cap', def: 'Companies with a market cap above ~$10B — typically stable, liquid, and slower-growing. The core of most index funds.' },
  { term: 'Small-Cap', aliases: ['small cap', 'petite capitalisation', 'small-cap'], category: 'markets', conceptId: 'market-cap', def: 'Companies with a small market cap (~$250M–$2B) — riskier and less liquid, but with higher growth potential. More of the market\'s long-run return comes from small caps.' },
  { term: 'Blue-Chip Stock', aliases: ['blue chip', 'valeur de premier rang', 'grande valeur'], category: 'markets', def: 'Shares of large, financially sound, well-known companies with long track records. Considered relatively safe equity holdings — the "household names" of the market.' },
  { term: 'Penny Stock', aliases: ['penny stock', 'action à quelques centimes', 'valeurs spéculatives'], category: 'markets', def: 'Shares of tiny, often troubled companies trading for pennies. Highly speculative, illiquid, and prone to manipulation — high risk of total loss.' },
  { term: 'Free Float', aliases: ['flottant', 'free float', 'capitalisation flottante'], category: 'markets', conceptId: 'market-cap', def: 'Shares available for the public to trade, excluding locked-up insider holdings. Indexes weight by free float so they reflect tradable market value.' },
  { term: 'Enterprise Value', aliases: ['valeur d\'entreprise', 'ev', 'enterprise value'], category: 'markets', conceptId: 'market-cap', def: 'The full price to buy a company: market cap + debt − cash. A better valuation anchor than market cap alone, because it accounts for how the company is financed.' },
  { term: 'Liquidity', aliases: ['liquidité', 'liquidités'], category: 'markets', conceptId: 'liquidity', def: 'How easily and cheaply you can turn an asset into cash at a fair price. Cash is perfectly liquid; real estate is not — and liquidity dries up exactly when you need it most.' },
  { term: 'Bid-Ask Spread', aliases: ['spread', 'fourchette bid ask', 'écart acheteur vendeur', 'spread acheteur vendeur'], category: 'markets', conceptId: 'liquidity', def: 'The gap between the best quoted buy (bid) and sell (ask) prices — a hidden tax on trading. Tight spread = liquid; wide spread = illiquid or risky.' },
  { term: 'Market Impact', aliases: ['impact de marché', 'slippage', 'glissement'], category: 'markets', conceptId: 'order-book', def: 'How much your own trade moves the price against you. Big orders in thin markets pay dearly — the cost of size that doesn\'t show in the quoted price.' },
  { term: 'Bull Market', aliases: ['marché haussier', 'bull market', 'hausse'], category: 'markets', conceptId: 'bull-bear-market', def: 'A prolonged period of rising prices and optimism. Markets spend most of history in bull territory — time in the market beats timing the market.' },
  { term: 'Bear Market', aliases: ['marché baissier', 'bear market', 'baisse'], category: 'markets', conceptId: 'bull-bear-market', def: 'A prolonged fall, conventionally −20% or more from a recent peak, with pessimism and often recession. The test of an investor — most returns come from staying invested through them.' },
  { term: 'Correction', aliases: ['correction', 'recul'], category: 'markets', conceptId: 'bull-bear-market', def: 'A drop of ~10% from a recent peak — smaller than a bear market, and a routine feature of healthy markets.' },
  { term: 'Dead-Cat Bounce', aliases: ['rebond mort', 'dead cat bounce', 'faux rebond'], category: 'markets', conceptId: 'bull-bear-market', def: 'A brief rally inside a falling market that traps early buyers. Not a recovery — just a pause in the decline.' },
  { term: 'Limit Order', aliases: ['ordre limité', 'limite', 'ordre à cours limité', 'limit'], category: 'markets', conceptId: 'order-book', def: 'An order to trade only at a specified price or better. It sits in the book providing liquidity, but may never fill.' },
  { term: 'Market Order', aliases: ['ordre à marché', 'market order', 'au marché'], category: 'markets', conceptId: 'order-book', def: 'An order to execute immediately at the best available price. It crosses the spread and takes liquidity — fast but you pay the spread.' },
  { term: 'Stop Order', aliases: ['stop', 'stop loss', 'ordre stop', 'stop à seuil'], category: 'markets', def: 'An order that becomes a market order once a trigger price is hit. Often used to cap losses ("stop-loss"), but in gaps it can fill far worse than the trigger.' },
  { term: 'Order Book', aliases: ['carnet d\'ordres', 'livre d\'ordres', 'order book', 'feuille de marché'], category: 'markets', conceptId: 'order-book', def: 'The real-time list of all outstanding buy and sell orders by price. The market\'s nervous system laid bare — where prices actually emerge from queued intent.' },
  { term: 'Dark Pool', aliases: ['dark pool', 'salle sombre', 'bourse alternative'], category: 'markets', conceptId: 'dark-pool', def: 'A private trading venue that doesn\'t display orders publicly, letting institutions trade big blocks without tipping off the market. Matches at the midpoint of the public spread.' },
  { term: 'Valuation', aliases: ['valorisation', 'évaluation', 'valuation'], category: 'markets', conceptId: 'valuation', def: 'Estimating what an asset is intrinsically worth, by discounting future cash flows or comparing to peers. The market price is an opinion; valuation is your independent check.' },
  { term: 'DCF', aliases: ['dcf', 'actualisation des flux de trésorerie', 'discounted cash flow', 'flux actualisés'], category: 'markets', conceptId: 'valuation', def: 'Discounted Cash Flow — valuing an asset as the present value of all its future cash flows. Precise-looking but dominated by the discount rate and growth assumptions you choose.' },
  { term: 'P/E Ratio', aliases: ['per', 'price earnings', 'ratio cours bénéfice', 'multiple de capitalisation', 'p/e'], category: 'markets', conceptId: 'pe-ratio', def: 'Price divided by earnings per share — how many years of current profit you pay per share. A quick "cheap or dear?" gauge, though earnings quality and growth matter as much as the number.' },
  { term: 'EV/EBITDA', aliases: ['ev ebitda', 'multiple d\'entreprise'], category: 'markets', def: 'Enterprise value divided by EBITDA — a valuation multiple that strips out capital structure and accounting differences. Widely used to compare companies across financing and tax regimes.' },
  { term: 'Price-to-Book', aliases: ['p/b', 'price to book', 'valeur comptable', 'ratio cours valeur comptable'], category: 'markets', def: 'Price divided by book value per share. A favorite of value investors for banks and asset-heavy firms — below 1 means you\'re buying assets for less than their accounting value.' },
  { term: 'Dividend Discount Model', aliases: ['ddm', 'modèle d\'actualisation des dividendes'], category: 'markets', def: 'Values a stock as the present value of all its future dividends. Cleanest in theory for dividend-payers, but very sensitive to the assumed long-run growth rate.' },
  { term: 'Margin of Safety', aliases: ['marge de sécurité', 'marge de sécurité', 'safety margin'], category: 'markets', def: 'Buying well below estimated intrinsic value, so being wrong about assumptions doesn\'t lose you money. Graham\'s core idea — the cushion for the unknowable.' },
  { term: 'Arbitrage', aliases: ['arbitrage'], category: 'markets', conceptId: 'arbitrage', def: 'Profiting from a price difference for the same (or equivalent) asset in two markets, with little risk. The "free lunch" that forces prices back into line — and is rarely free or easy.' },
  { term: 'Speculation', aliases: ['spéculation', 'spéculer'], category: 'markets', def: 'Taking on risk in hopes of profit from price moves, without hedging an existing exposure. Unlike investing, it\'s a bet on price, not on underlying value or cash flows.' },
  { term: 'Short Squeeze', aliases: ['short squeeze', 'resserrement de positions courtes'], category: 'markets', conceptId: 'short-selling', def: 'A feedback loop where rising prices force short sellers to buy back and cover, pushing prices higher still. Can multiply losses in days — the asymmetric danger of shorting.' },
  { term: 'Yield Curve', aliases: ['courbe des taux', 'yield curve', 'structure des taux'], category: 'banking', conceptId: 'yield-curve', def: 'The line of interest rates across maturities (from overnight to 30-year bonds). Its shape — normally upward sloping — signals the market\'s growth and rate expectations.' },
  { term: 'Inverted Yield Curve', aliases: ['courbe inversée', 'inverted curve', 'courbe des taux inversée'], category: 'banking', conceptId: 'yield-curve', def: 'When long rates fall below short rates. A historically reliable recession signal — the market is pricing rate cuts ahead, which usually means trouble.' },
  { term: 'Contango', aliases: ['contango', 'report'], category: 'derivatives', conceptId: 'futures', def: 'When a futures price is above the spot price (the curve slopes up). Normal for storable assets carrying financing and storage costs.' },
  { term: 'Backwardation', aliases: ['backwardation', 'déport'], category: 'derivatives', conceptId: 'futures', def: 'When a futures price is below the spot price. Signals scarcity now — the physical is in demand, so deferred delivery is cheaper.' },
  { term: 'Market Index', aliases: ['indice boursier', 'index', 'indice'], category: 'markets', def: 'A statistic tracking the performance of a group of assets, like the S&P 500 or CAC 40. The benchmark against which managers and markets are measured.' },
  { term: 'IPO', aliases: ['introduction en bourse', 'ipo', 'initial public offering', 'ouvertue au public'], category: 'markets', conceptId: 'ipo', def: 'Initial Public Offering — a private company selling shares to the public for the first time. The transition to being a listed, publicly traded company.' },
  { term: 'Secondary Offering', aliases: ['offre secondaire', 'augmentation de capital'], category: 'markets', def: 'A company already public selling more shares. Dilutes existing holders but raises fresh capital — distinct from the IPO.' },
  { term: 'Lock-Up Period', aliases: ['période de blocage', 'lock-up', 'période d\'interdiction de vente'], category: 'markets', conceptId: 'ipo', def: 'A window after an IPO when insiders cannot sell their shares, preventing a flood of selling. When it expires, the stock often wobbles.' },
  { term: 'SPAC', aliases: ['spac', 'acquisition à but spécial'], category: 'markets', def: 'A "blank-check" company that raises money to merge with a private firm and take it public — an IPO alternative. Fast and flexible, but with a checkered record.' },

  /* ---------------- PERSONAL ---------------- */
  { term: 'Budgeting', aliases: ['budget', 'budgétisation', 'tenir un budget'], category: 'personal', conceptId: 'budgeting-50-30-20', def: 'Planning how income is spent and saved. The 50/30/20 rule splits after-tax pay into needs, wants, and the future — simple enough to actually follow.' },
  { term: 'Emergency Fund', aliases: ['fonds d\'urgence', 'fonds de précaution', 'épargne de précaution', 'cagnotte de sécurité'], category: 'personal', conceptId: 'emergency-fund', def: 'A cash stash of 3–6 months of essential expenses for surprises. Not invested — its job is to be there, unchanged, so a crisis becomes an inconvenience, not a disaster.' },
  { term: 'Credit Score', aliases: ['score de crédit', 'cote de crédit', 'notation particuliers'], category: 'personal', conceptId: 'credit-score', def: 'A number predicting how likely you are to repay borrowed money. Lenders use it to set rates — a higher score saves tens of thousands on a mortgage.' },
  { term: 'Credit Utilization', aliases: ['taux d\'utilisation du crédit', 'utilization ratio', 'taux d\'endettement carte'], category: 'personal', conceptId: 'credit-score', def: 'Balance ÷ credit limit on your cards. Keep it below 30% (lower is better) — a big driver of your credit score that you control directly.' },
  { term: 'Net Worth', aliases: ['patrimoine', 'valeur nette', 'situation patrimoniale'], category: 'personal', def: 'Everything you own (assets) minus everything you owe (liabilities). The single number that summarizes your financial position — track it over time, not month to month.' },
  { term: 'Pay Yourself First', aliases: ['se payer en premier', 'épargne automatique', 'pay yourself first'], category: 'personal', conceptId: 'budgeting-50-30-20', def: 'Save or invest on payday before any discretionary spending, by automation. Never rely on "what\'s left" — there is never anything left.' },
  { term: 'High-Yield Savings', aliases: ['livret à taux boosté', 'compte à intérêts', 'high yield savings'], category: 'personal', conceptId: 'emergency-fund', def: 'A savings account paying a competitive rate, still guaranteed and liquid. The right home for an emergency fund — yield without risking the principal.' },
  { term: 'Debt Avalanche', aliases: ['avalanche de dettes', 'méthode avalanche'], category: 'personal', def: 'Repaying debts from highest interest rate down — the mathematically cheapest way to clear debt. Saves the most money but can feel slow on small balances.' },
  { term: 'Debt Snowball', aliases: ['boule de neige des dettes', 'méthode boule de neige'], category: 'personal', def: 'Repaying debts from smallest balance up — the psychologically easiest way. Costs a bit more in interest but wins on motivation and follow-through.' },
  { term: 'Refinancing', aliases: ['renégociation', 'refinancement', 'rachat de crédit'], category: 'banking', conceptId: 'amortization', def: 'Replacing an old loan with a new one, usually for a lower rate. Can cut payments — but resetting a long mortgage term can raise lifetime interest even as the monthly falls.' },
  { term: 'FIRE Movement', aliases: ['fire', 'indépendance financière', 'financial independence retire early'], category: 'personal', def: 'Financial Independence, Retire Early — aggressive saving (~50%+ of income) to reach financial freedom decades early. A lifestyle built on a high savings rate and low-cost investing.' },
  { term: 'Robo-Advisor', aliases: ['robo advisor', 'conseiller automatisé', 'gestion automatisée'], category: 'personal', def: 'A digital service that builds and rebalances a portfolio for you algorithmically, for a low fee. Cheap, diversified, hands-off investing — ideal for those who want zero involvement.' },
  { term: 'Tax-Loss Harvesting', aliases: ['récolte des moins-values', 'harvesting', 'compensation fiscale'], category: 'personal', def: 'Selling losers to realize losses that offset taxable gains, then repositioning. A legal tax-deferral technique — valuable, but not the free lunch it first appears.' },

  /* ---------------- CORPORATE ---------------- */
  { term: 'Leverage', aliases: ['effet de levier', 'levier', 'gearing', 'levier financier'], category: 'corporate', conceptId: 'leverage', def: 'Using borrowed money to amplify returns — it magnifies gains and losses equally, and can turn a survivable loss into a fatal one. The single most common way capable people go broke.' },
  { term: 'Capital Structure', aliases: ['structure de capital', 'structure financière'], category: 'corporate', conceptId: 'leverage', def: 'A company\'s mix of debt and equity funding. The optimal mix trades the tax shield of debt against the bankruptcy cost of too much debt.' },
  { term: 'Tax Shield', aliases: ['bouclier fiscal', 'tax shield', 'économie d\'impôt liée à la dette'], category: 'corporate', conceptId: 'leverage', def: 'The tax saving from deducting interest payments. Debt is subtly attractive because interest is tax-deductible while dividends are not — and subtly risky for the same reason.' },
  { term: 'Working Capital', aliases: ['besoin en fonds de roulement', 'bfr', 'fonds de roulement', 'working capital'], category: 'corporate', conceptId: 'working-capital', def: 'Current assets minus current liabilities — the short-term money tied up in running the business. A profitable firm can still go bust if cash gets stuck in inventory or slow-paying customers.' },
  { term: 'Cash Conversion Cycle', aliases: ['cycle de conversion de trésorerie', 'cycle d\'exploitation', 'ccc'], category: 'corporate', conceptId: 'working-capital', def: 'How long a euro is tied up from buying inventory to collecting cash: inventory days + receivable days − payable days. Lower (even negative) is better — some great businesses are funded by it.' },
  { term: 'Earnings Quality', aliases: ['qualité du résultat', 'quality of earnings'], category: 'corporate', conceptId: 'working-capital', def: 'How reliably accounting profit turns into actual cash. If net income rises but cash flow lags, money is stuck in receivables or inventory — a quiet red flag.' },
  { term: 'LBO', aliases: ['lbo', 'rachat avec effet de levier', 'leveraged buyout', 'rachat à effet de levier'], category: 'corporate', conceptId: 'lbo', def: 'Leveraged Buyout — acquiring a company using mostly borrowed money, with the target\'s own cash flow repaying the debt. Private equity\'s signature move — high return if it works, high risk if it doesn\'t.' },
  { term: 'WACC', aliases: ['cmpc', 'coût moyen pondéré du capital', 'weighted average cost of capital'], category: 'corporate', def: 'The blended cost of a company\'s debt and equity financing. The discount rate used to value its projects — a project is worth doing only if its return exceeds the WACC.' },
  { term: 'Return on Equity', aliases: ['roe', 'rentabilité des capitaux propres', 'return on equity'], category: 'corporate', def: 'Net income ÷ shareholder equity — the profit generated per unit of owners\' capital. A core measure of how efficiently a company uses its owners\' money.' },
  { term: 'Return on Invested Capital', aliases: ['roic', 'rentabilité du capital investi'], category: 'corporate', def: 'Profit ÷ all capital invested (debt + equity). The cleanest measure of whether a company earns more than its cost of capital — the test of genuine value creation.' },
  { term: 'EBITDA', aliases: ['ebitda', 'résultat avant intérêts impôts dépréciation amortissement'], category: 'accounting', def: 'Earnings Before Interest, Taxes, Depreciation, and Amortization — a rough proxy for operating cash flow. Loved for comparability, distrusted because it ignores the real cost of capital and depreciation.' },
  { term: 'Free Cash Flow', aliases: ['free cash flow', 'fcf', 'flux de trésorerie disponible'], category: 'corporate', def: 'Cash a company generates after funding its operations and capex — what is truly left for debt and shareholders. The number valuation should really be built on, not reported earnings.' },
  { term: 'Capital Expenditure', aliases: ['capex', 'investissement corporel', 'dépenses d\'investissement'], category: 'corporate', def: 'Money spent on long-lived assets (factories, equipment, software) rather than day-to-day operations. An investment for the future, expensed over time rather than all at once.' },
  { term: 'Shareholder', aliases: ['actionnaire', 'porteur d\'actions'], category: 'corporate', def: 'An owner of shares in a company. Shareholders bear the residual risk and claim the residual profit — last in line in bankruptcy, first in line for upside.' },
  { term: 'Dividend Policy', aliases: ['politique de dividende', 'politique de distribution'], category: 'corporate', def: 'A company\'s approach to how much profit it returns vs. reinvests. Signals management\'s view of growth opportunities — a sticky, hard-to-cut dividend is a confidence signal.' },

  /* ---------------- ACCOUNTING (new category) ---------------- */
  { term: 'Balance Sheet', aliases: ['bilan', 'bilan comptable', 'balance sheet'], category: 'accounting', conceptId: 'balance-sheet', def: 'A snapshot of what a company owns (assets) and owes (liabilities) at one moment, with equity as the difference. The financial photograph — everything else is motion.' },
  { term: 'Income Statement', aliases: ['compte de résultat', 'income statement', 'compte d\'exploitation', 'profit and loss', 'p&l'], category: 'accounting', conceptId: 'income-statement', def: 'A record of revenue minus expenses over a period, ending in profit or loss. The movie of performance — shows how the business did, not what it is worth.' },
  { term: 'Cash Flow Statement', aliases: ['tableau des flux de trésorerie', 'cash flow statement', 'flux de trésorerie'], category: 'accounting', def: 'Tracks actual cash in and out across operating, investing, and financing activities. Reconciles accounting profit with real cash — the lie detector for earnings.' },
  { term: 'Revenue', aliases: ['chiffre d\'affaires', 'revenu', 'ca', 'sales'], category: 'accounting', def: 'The total money earned from selling goods or services before any costs. The top line — growth here matters, but profit matters more.' },
  { term: 'Net Income', aliases: ['résultat net', 'bénéfice net', 'profit', 'earnings', 'résultat de l\'exercice'], category: 'accounting', def: 'What remains after all costs, taxes, and interest — the bottom line. The accounting profit, but not necessarily the cash generated.' },
  { term: 'EBIT', aliases: ['ebit', 'résultat d\'exploitation', 'operating profit', 'résultat opérationnel'], category: 'accounting', def: 'Earnings Before Interest and Taxes — operating profit, before financing and tax effects. Isolates the performance of the business itself from how it is financed.' },
  { term: 'Depreciation', aliases: ['amortissement', 'dépréciation', 'depreciation'], category: 'accounting', def: 'Spreading the cost of a long-lived asset over its useful life. A non-cash expense that reduces reported profit but doesn\'t spend cash — why earnings can exceed cash flow.' },
  { term: 'Amortization (intangibles)', aliases: ['amortissement (intangibles)', 'amortissement financier', 'amortissement des immobilisations incorporelles'], category: 'accounting', def: 'Like depreciation but for intangible assets (patents, goodwill) — spreading their cost over their useful life. Distinct from loan amortization, which is the schedule of loan repayments.' },
  { term: 'Goodwill', aliases: ['goodwill', 'survaleur', 'écart d\'acquisition'], category: 'accounting', def: 'The premium paid in an acquisition above the fair value of net assets — the price of brand, talent, synergies. Written down if the acquisition disappoints (an impairment charge).' },
  { term: 'Book Value', aliases: ['valeur comptable', 'book value', 'capitaux propres par action'], category: 'accounting', def: 'Net assets on the balance sheet — what the accounting says the company is worth. Often far from market value, which is why price-to-book can spot bargains (or traps).' },
  { term: 'GAAP', aliases: ['gaap', 'principes comptables generally accepted', 'us gaap'], category: 'accounting', def: 'Generally Accepted Accounting Principles — the U.S. accounting rulebook. Defines how revenue, costs, and profit must be reported for comparability.' },
  { term: 'IFRS', aliases: ['ifrs', 'normes comptables internationales'], category: 'accounting', def: 'International Financial Reporting Standards — the global accounting rulebook used in the EU and most of the world. The counterpart to U.S. GAAP.' },
  { term: 'Audit', aliases: ['audit', 'contrôle des comptes', 'révision'], category: 'accounting', def: 'An independent examination of a company\'s financial statements. The auditor\'s opinion gives the numbers credibility — without it, reported earnings are just self-reported.' },
  { term: 'Accrual Accounting', aliases: ['comptabilité d\'engagement', 'comptabilité d\'exercice', 'accrual'], category: 'accounting', def: 'Recording revenue when earned and costs when incurred, regardless of when cash moves. The basis of modern accounting — and the reason profit ≠ cash.' },
  { term: 'Off-Balance-Sheet', aliases: ['hors bilan', 'off balance sheet'], category: 'accounting', def: 'Items or exposures not shown as assets/liabilities on the balance sheet. Legitimately used for operating leases or guarantees, but historically a way to hide leverage — now sharply restricted.' },

  /* ---------------- BANKING & CREDIT ---------------- */
  { term: 'Interest Rate', aliases: ['taux d\'intérêt', 'taux', 'interest rate'], category: 'banking', conceptId: 'interest-rate', def: 'The price of borrowing money, as a yearly percentage. The gravity of finance — when it moves, every loan, bond, and stock reprices at once.' },
  { term: 'APR', aliases: ['taeg', 'taux annuel effectif global', 'annual percentage rate', 'apr'], category: 'banking', conceptId: 'interest-rate', def: 'Annual Percentage Rate — the yearly cost of borrowing including fees, but often excluding compounding. The headline rate on a loan; read the APY too.' },
  { term: 'APY', aliases: ['taux annuel effectif (apy)', 'apy', 'annual percentage yield'], category: 'banking', conceptId: 'interest-rate', def: 'Annual Percentage Yield — the yearly return including compounding. The true cost or gain — always compare APY to APY, not to the headline APR.' },
  { term: 'Amortization', aliases: ['amortissement (prêt)', 'amortissement du capital', 'tableau d\'amortissement'], category: 'banking', conceptId: 'amortization', def: 'Spreading loan repayment into fixed installments where the interest share falls and principal share rises over time. Why early mortgage payments barely dent the balance.' },
  { term: 'Principal', aliases: ['principal', 'capital (d\'un prêt)', 'montant en principal'], category: 'banking', conceptId: 'amortization', def: 'The original amount borrowed or invested, separate from interest. Paying down principal is what actually retires a loan.' },
  { term: 'Coupon', aliases: ['coupon', 'intérêt obligataire'], category: 'banking', conceptId: 'bond', def: 'The regular interest payment a bond makes, often fixed. The income stream; the bond\'s price moves around it as rates change.' },
  { term: 'Yield', aliases: ['rendement', 'yield', 'taux de rendement'], category: 'banking', conceptId: 'bond', def: 'The income return on an investment, usually annualized. Bond yield rises when price falls — they are two views of the same thing.' },
  { term: 'Yield to Maturity', aliases: ['rendement à échéance', 'ytm', 'yield to maturity'], category: 'banking', conceptId: 'bond', def: 'The total annualized return if a bond is held to the end and coupons are reinvested at the same rate. The honest bond quote — but assumes things that aren\'t guaranteed.' },
  { term: 'Duration', aliases: ['duration', 'sensibilité (obligation)'], category: 'banking', conceptId: 'bond', def: 'A bond\'s price sensitivity to rate changes, expressed in years. Longer duration = bigger swings when rates move — why long bonds can be among the riskiest assets in a rate shock.' },
  { term: 'Bond', aliases: ['obligation', 'titre de dette'], category: 'banking', conceptId: 'bond', def: 'A tradable IOU: you lend money, receive regular interest (coupons), and get principal back at maturity. Prices move opposite to rates; credit and rate risk dominate.' },
  { term: 'Sovereign Bond', aliases: ['obligation souveraine', 'obligation d\'état', 'treasury', 'gilt', 'obligation assimilable'], category: 'banking', conceptId: 'bond', def: 'Debt issued by a national government — the safest bonds, the benchmark "risk-free" rate. Treasuries (US), Bunds (Germany), Gilts (UK), OATs (France).' },
  { term: 'Corporate Bond', aliases: ['obligation d\'entreprise', 'corporate bond'], category: 'banking', conceptId: 'bond', def: 'Debt issued by a company — riskier than government bonds, so it pays a higher yield. The extra yield is the credit spread, compensation for default risk.' },
  { term: 'High-Yield Bond', aliases: ['obligation à haut rendement', 'junk bond', 'obligation pourrie', 'high yield'], category: 'banking', def: 'Bonds rated below investment grade — higher yield for higher default risk. The "junk" label; profitable when the economy holds up, punishing in recession.' },
  { term: 'Credit Rating', aliases: ['notation financière', 'rating', 'note de crédit', 'notation'], category: 'banking', def: 'A grade (AAA down to D) assessing a borrower\'s ability to repay. Set by agencies (S&P, Moody\'s, Fitch); drives borrowing costs — downgrades raise them sharply.' },
  { term: 'Credit Spread', aliases: ['spread de crédit', 'prime de crédit'], category: 'banking', def: 'The extra yield a corporate bond pays over a government bond of the same maturity. Measures perceived default risk — widening spreads signal fear in credit markets.' },
  { term: 'Mortgage', aliases: ['hypothèque', 'prêt immobilier', 'mortgage', 'crédit immobilier'], category: 'banking', conceptId: 'amortization', def: 'A loan secured by real estate, amortized over many years. The largest debt most people ever take — its rate and term shape decades of finances.' },
  { term: 'Securitization', aliases: ['titrisation', 'securitization'], category: 'banking', conceptId: 'securitization', def: 'Bundling loans (mortgages, auto, credit cards) into bonds sold to investors. Turns illiquid loans into tradable securities — powerful, and the mechanism behind the 2008 crisis.' },
  { term: 'MBS', aliases: ['mbs', 'mortgage backed security', 'titrisation hypothécaire', 'titrisation de créances hypothécaires'], category: 'banking', conceptId: 'securitization', def: 'Mortgage-Backed Security — a bond whose payments come from a pool of mortgages. The instrument at the heart of the 2008 crisis; sound when underwriting is sound.' },
  { term: 'CDO', aliases: ['cdo', 'collateralized debt obligation', 'obligation adossée à des créances'], category: 'banking', def: 'Collateralized Debt Obligation — a security slicing pooled debts into tranches of varying risk. The infamous "slicing and dicing" that hid subprime risk in 2008.' },
  { term: 'Tranche', aliases: ['tranche', 'tranche (titrisation)'], category: 'banking', conceptId: 'securitization', def: 'A slice of a securitized deal with a defined risk and return — senior tranches are paid first (safer), equity tranches last (riskiest). Same pool, opposite ends of the risk spectrum.' },
  { term: 'Repo', aliases: ['repo', 'accord de rachat', 'pension livrée', 'mise en pension'], category: 'banking', conceptId: 'repo', def: 'Repurchase Agreement — a short-term collateralized loan: sell a bond today, agree to buy it back tomorrow at a higher price. The overnight plumbing of Wall Street.' },
  { term: 'Interbank Rate', aliases: ['taux interbancaire', 'euribor', 'sofr', 'libor', 'taux du marché monétaire'], category: 'banking', def: 'The rate at which banks lend to each other overnight (Euribor, SOFR, former Libor). The benchmark floating rate that mortgages and swaps reference.' },
  { term: 'Bank Run', aliases: ['bank run', 'ruée bancaire', 'retrait de panique'], category: 'banking', def: 'When depositors all withdraw at once, fearing the bank will fail — a fear that becomes self-fulfilling. Deposit insurance and lender-of-last-resort exist to stop it.' },

  /* ---------------- ECONOMICS ---------------- */
  { term: 'GDP', aliases: ['pib', 'produit intérieur brut', 'gdp', 'produit interieur brut'], category: 'economics', conceptId: 'gdp', def: 'Gross Domestic Product — the total value of goods and services a country produces in a year. The headline number for economic size; real GDP (adjusted for inflation) shows growth.' },
  { term: 'Recession', aliases: ['récession', 'recession'], category: 'economics', conceptId: 'gdp', def: 'A sustained downturn, commonly two quarters of falling real GDP. The end of an expansion; the test for policy, businesses, and portfolios.' },
  { term: 'Depression', aliases: ['dépression économique', 'depression'], category: 'economics', def: 'A severe, prolonged recession with deep output loss and high unemployment — like the 1930s. There is no formal threshold; it is a recession that won\'t end.' },
  { term: 'Supply & Demand', aliases: ['offre et demande', 'supply demand', 'loi de l\'offre et de la demande'], category: 'economics', conceptId: 'supply-demand', def: 'The model at the heart of all pricing: prices settle where the quantity buyers want equals the quantity sellers offer. Almost every price change is a supply-and-demand story underneath.' },
  { term: 'Elasticity', aliases: ['élasticité', 'élasticité prix'], category: 'economics', conceptId: 'supply-demand', def: 'How much quantity reacts to price. Inelastic goods (insulin, fuel) absorb price changes with little quantity change — so shocks hit price hard, and so do taxes on them.' },
  { term: 'Monetary Policy', aliases: ['politique monétaire', 'monetary policy'], category: 'economics', conceptId: 'central-bank', def: 'Central bank actions — setting rates and the money supply — to steer inflation and growth. Tightens to cool, loosens to stimulate.' },
  { term: 'Fiscal Policy', aliases: ['politique budgétaire', 'fiscal policy', 'politique fiscale'], category: 'economics', def: 'Government taxing and spending to influence the economy. The counterpart to monetary policy — spending more or taxing less to stimulate, the reverse to restrain.' },
  { term: 'Quantitative Easing', aliases: ['assouplissement quantitatif', 'qe', 'quantitative easing'], category: 'economics', conceptId: 'central-bank', def: 'When rates hit zero, the central bank buys bonds to pump money into the system. "Printing money" in sophisticated form — prevents depressions but inflates asset prices.' },
  { term: 'Fiat Money', aliases: ['monnaie fiduciaire', 'fiat', 'monnaie fiat', 'monnaie légale'], category: 'economics', conceptId: 'fiat-money', def: 'Money that has value because a government decrees it, not because it is backed by gold or another asset. All modern currencies are fiat — their worth rests on trust in the issuing state.' },
  { term: 'Deficit', aliases: ['déficit', 'déficit budgétaire', 'budget deficit'], category: 'economics', def: 'When a government spends more than it collects in taxes in a year. The shortfall is borrowed, adding to the national debt.' },
  { term: 'National Debt', aliases: ['dette publique', 'dette souveraine', 'national debt', 'dette de l\'état'], category: 'economics', def: 'The total a government owes, accumulated from years of deficits. Sustainable if growth outpaces interest costs; dangerous when debt service consumes the budget.' },
  { term: 'Trade Balance', aliases: ['balance commerciale', 'solde commercial', 'trade balance'], category: 'economics', conceptId: 'gdp', def: 'Exports minus imports. A deficit (imports exceed exports) isn\'t inherently bad — it often reflects a strong, consuming economy — but persistent deficits build foreign debt.' },
  { term: 'Current Account', aliases: ['balance des paiements courants', 'balance courante', 'current account'], category: 'economics', def: 'A country\'s trade in goods and services plus income and transfers. The broadest measure of cross-border flows; a persistent deficit must be funded by foreign capital.' },
  { term: 'Unemployment', aliases: ['chômage', 'taux de chômage', 'unemployment rate'], category: 'economics', def: 'The share of the labor force without a job and looking for one. A key macro indicator; low unemployment usually signals a strong economy, sometimes inflationary.' },
  { term: 'Phillips Curve', aliases: ['courbe de phillips', 'phillips curve'], category: 'economics', def: 'The observed trade-off between unemployment and inflation — lower unemployment tends to come with higher inflation. The relationship has been unstable, but the intuition endures.' },
  { term: 'Productivity', aliases: ['productivité', 'productivité du travail'], category: 'economics', def: 'Output per hour worked. The ultimate driver of long-run living standards — only by producing more per hour can a country get richer without working more.' },
  { term: 'Moral Hazard', aliases: ['aléa moral', 'risque moral', 'moral hazard'], category: 'economics', def: 'When being insured against a risk makes people take more of it. Why banks that expect bailouts take bigger risks — the core argument against unconditional rescues.' },
  { term: 'M2 Money Supply', aliases: ['masse monétaire m2', 'm2', 'agrégat monétaire'], category: 'economics', def: 'A broad measure of money: cash plus most deposits. Tracking its growth helps read inflation pressure — too-fast money growth chases too-slow goods.' },

  /* ---------------- RISK & BEHAVIOR ---------------- */
  { term: 'Risk Management', aliases: ['gestion des risques', 'gestion du risque', 'risk management'], category: 'risk', conceptId: 'risk-management', def: 'Identifying, measuring, and deliberately handling the risks you face — avoid, reduce, transfer (insure), or accept. The goal is not zero risk but no ruinous risk.' },
  { term: 'Hedging', aliases: ['couverture', 'hedging', 'se couvrir'], category: 'risk', conceptId: 'hedging', def: 'Taking an offsetting position so gains cancel the losses of a risk you already hold. Not a bet on being right — a bet on not being ruined.' },
  { term: 'Basis Risk', aliases: ['risque de base', 'basis risk'], category: 'risk', conceptId: 'hedging', def: 'The risk that a hedge doesn\'t perfectly track the exposure — the residual gap. Perfect hedges are rare; this is the leftover risk hedgers must live with.' },
  { term: 'Insurance', aliases: ['assurance', 'insurance'], category: 'risk', conceptId: 'risk-management', def: 'Paying a small certain premium to avoid an unaffordable loss. Insure what you cannot afford to lose; self-insure (skip) what you can — extended warranties fail this test.' },
  { term: 'Self-Insurance', aliases: ['auto-assurance', 'self insurance'], category: 'risk', conceptId: 'risk-management', def: 'Covering small risks from your own savings instead of paying premiums. The emergency fund is a form of self-insurance against life\'s routine surprises.' },
  { term: 'Behavioral Finance', aliases: ['finance comportementale', 'behavioral finance'], category: 'risk', conceptId: 'behavioral-finance', def: 'The study of how real people systematically deviate from rational money decisions. The biggest risk to your wealth is usually you — biases are systematic, hence avoidable.' },
  { term: 'Loss Aversion', aliases: ['aversion à la perte', 'loss aversion'], category: 'risk', conceptId: 'behavioral-finance', def: 'A loss feels roughly twice as bad as an equal gain feels good. Explains why we sell winners too early and hold losers too long — the opposite of what works.' },
  { term: 'Recency Bias', aliases: ['biais de récence', 'recency bias'], category: 'risk', conceptId: 'behavioral-finance', def: 'Overweighting recent events when judging the future. Makes us pile into what just rose and flee what just fell — buying high, selling low.' },
  { term: 'Anchoring', aliases: ['ancrage', 'ancrage mental', 'anchoring'], category: 'risk', conceptId: 'behavioral-finance', def: 'Clinging to an irrelevant reference price (what you paid, the old high). "Wait until it comes back" is anchoring to a sunk cost — a costly illusion.' },
  { term: 'Mental Accounting', aliases: ['comptabilité mentale', 'mental accounting'], category: 'risk', conceptId: 'behavioral-finance', def: 'Treating the same money differently depending on its source or label ("house money," "found money"). A costly illusion — a euro is a euro wherever it sits.' },
  { term: 'Herding', aliases: ['comportement moutonnier', 'herd behavior', 'effet de meute'], category: 'risk', conceptId: 'behavioral-finance', def: 'Copying the crowd. Feeds bubbles and panics — safety in numbers feels right, but the crowd is often wrong at the extremes.' },
  { term: 'Confirmation Bias', aliases: ['biais de confirmation', 'confirmation bias'], category: 'risk', def: 'Seeking information that agrees with your view and ignoring what contradicts it. The reason a confident investor can be a badly-informed one.' },
  { term: 'Disposition Effect', aliases: ['effet de disposition', 'disposition effect'], category: 'risk', def: 'The tendency to sell winners too early and hold losers too long — driven by loss aversion. The exact opposite of "cut your losers, let your winners run."' },
  { term: 'Risk Capacity', aliases: ['capacité de risque', 'risk capacity'], category: 'risk', conceptId: 'risk-vs-return', def: 'How much loss you can financially afford to take. Should drive allocation more than risk tolerance (how much loss you can stomach) — capacity is objective, tolerance is emotional.' },

  /* ---------------- INSTITUTIONS ---------------- */
  { term: 'Broker', aliases: ['courtier', 'broker', 'intermédiaire financier'], category: 'institutions', conceptId: 'broker', def: 'A licensed intermediary who executes buy and sell orders for an investor, for a commission or fee. Bridges the gap between you and the exchange.' },
  { term: 'Discount Broker', aliases: ['courtier à frais réduits', 'broker en ligne', 'courtier en ligne'], category: 'institutions', conceptId: 'broker', def: 'A low-cost broker offering execution without personalized advice. Modern apps took this further with zero commissions — the cost moved, it didn\'t vanish.' },
  { term: 'Payment for Order Flow', aliases: ['pfof', 'paiement pour flux d\'ordres'], category: 'institutions', conceptId: 'broker', def: 'When a broker sells your orders to a market maker, who profits from the spread. How "free" trades are really funded — the cost is hidden in execution.' },
  { term: 'Fiduciary', aliases: ['fiduciaire', 'fiduciary duty', 'obligation fiduciaire', 'devoir fiduciaire'], category: 'institutions', conceptId: 'broker', def: 'A legal obligation to act in the client\'s best interest, not the firm\'s. A stronger standard than mere "suitability" — the line that separates advice from sales.' },
  { term: 'Depositary', aliases: ['dépositaire', 'custodian', 'gardien d\'actifs', 'dépositaire central'], category: 'institutions', conceptId: 'depositary', def: 'An institution that holds and safeguards a client\'s assets, separate from the broker. If the broker fails, your assets are still yours — that separation is the point.' },
  { term: 'Central Securities Depositary', aliases: ['cct', 'dépositaire central', 'csd', 'euroclear', 'clearstream'], category: 'institutions', conceptId: 'depositary', def: 'The core ledger that records who owns which securities at the system level (Euroclear, Clearstream). The backbone of dematerialized ownership.' },
  { term: 'Central Bank', aliases: ['banque centrale', 'central bank', 'banque des banques'], category: 'institutions', conceptId: 'central-bank', def: 'A national authority managing currency, money supply, and rates to ensure stability — the ECB, the Fed. The "bank of banks"; the only entity that can create base money.' },
  { term: 'Lender of Last Resort', aliases: ['prêteur en dernier ressort', 'lender of last resort'], category: 'institutions', conceptId: 'central-bank', def: 'The central bank\'s role in lending to solvent but illiquid banks during a panic. Stops bank runs becoming systemic collapses — at a price (penalty rate, good collateral).' },
  { term: 'Clearing House', aliases: ['chambre de compensation', 'clearing house', 'ccp', 'contrepartie centrale'], category: 'institutions', conceptId: 'clearing-house', def: 'An intermediary that guarantees a trade, becoming buyer to every seller and seller to every buyer. Removes counterparty risk and nets positions across the system.' },
  { term: 'Counterparty', aliases: ['contrepartie', 'counterparty'], category: 'institutions', conceptId: 'counterparty', def: 'The other side of your trade — whoever owes you performance. Your profit is only as good as their promise; counterparty risk is the chance they default.' },
  { term: 'Counterparty Risk', aliases: ['risque de contrepartie', 'risque de défaut', 'counterparty risk'], category: 'institutions', conceptId: 'counterparty', def: 'The chance the other party fails to honor a contract before paying you. Central to all OTC dealing; mitigated by collateral, netting, and clearing.' },
  { term: 'Fund', aliases: ['fond', 'fonds', 'fonds commun de placement', 'fcp', 'opcvm', 'sicav', 'mutual fund', 'investment fund'], category: 'institutions', conceptId: 'fund', def: 'A pooled investment vehicle: many investors\' money buys one diversified portfolio, each owning a slice. Turns €100 into institutional-grade diversification.' },
  { term: 'NAV', aliases: ['valeur nette d\'inventaire', 'vni', 'net asset value', 'nav'], category: 'institutions', conceptId: 'fund', def: 'Net Asset Value — a fund\'s per-share worth: (assets − liabilities) ÷ shares. Struck daily for mutual funds, continuously for ETFs via on-exchange trading.' },
  { term: 'Open-Ended Fund', aliases: ['fonds ouvert', 'open ended fund', 'opcvm'], category: 'institutions', conceptId: 'fund', def: 'A fund that creates and redeems shares on demand, keeping price near NAV. The normal structure for mutual funds and most ETFs.' },
  { term: 'Closed-Ended Fund', aliases: ['fonds fermé', 'closed end fund'], category: 'institutions', def: 'A fund with a fixed number of shares trading on an exchange. Price can drift above or below NAV — sometimes a bargain, sometimes a trap.' },
  { term: 'Hedge Fund', aliases: ['hedge fund', 'fonds alternatif', 'fonds de couverture', 'fonds spéculatif'], category: 'institutions', conceptId: 'hedge-fund', def: 'A lightly regulated private fund using flexible, often leveraged strategies for high net-worth and institutional investors. "2 and 20" fees; high reward if skilled, high risk and illiquidity regardless.' },
  { term: 'Private Equity', aliases: ['capital investissement', 'private equity', 'capital investissement', 'non coté'], category: 'institutions', conceptId: 'private-equity', def: 'Investing in private (non-listed) companies, often improving and selling them years later. Uses leverage (LBOs) and lock-ups; high returns sought in exchange for illiquidity.' },
  { term: 'Venture Capital', aliases: ['capital risque', 'capital-risque', 'venture capital', 'vc'], category: 'institutions', conceptId: 'venture-capital', def: 'Equity funding for young, high-growth startups in exchange for a stake. Most bets fail; a few winners return the fund — power-law investing.' },
  { term: 'Pension Fund', aliases: ['fonds de pension', 'caisse de retraite', 'pension fund'], category: 'institutions', def: 'A pool of money investing on behalf of members to pay retirement benefits. Among the largest institutional investors, with the longest horizons — they can hold illiquid assets others can\'t.' },
  { term: 'Sovereign Wealth Fund', aliases: ['fonds souverain', 'fonds de richesse souverain', 'swf'], category: 'institutions', def: 'A state-owned investment fund holding national assets (often from commodity or FX reserves). Giant, long-horizon, politically influential investors.' },
  { term: 'Asset Manager', aliases: ['société de gestion', 'gestionnaire d\'actifs', 'asset manager', 'gérant d\'actifs'], category: 'institutions', conceptId: 'asset-manager', def: 'A firm that invests pooled money on behalf of clients for a fee. Active tries to beat a benchmark; passive replicates one cheaply — the industry has shifted hard toward passive.' },
  { term: 'Client', aliases: ['client', 'investisseur', 'souscripteur', 'particulier', 'investisseur particulier'], category: 'institutions', conceptId: 'client', def: 'The end owner of the money, on whose behalf brokers, custodians, and managers act. The principal everyone else is, in theory, serving — and the only one bearing the losses.' },
  { term: 'Market Maker', aliases: ['apporteur de liquidité', 'market maker', 'teneur de marché', 'teneur de marché'], category: 'institutions', conceptId: 'market-maker', def: 'A firm continuously quoting both a buy and a sell price, profiting from the spread. Provides the instant liquidity that lets others trade now — bears inventory risk in return.' },
  { term: 'Prime Broker', aliases: ['prime broker', 'courtier principal'], category: 'institutions', conceptId: 'prime-broker', def: 'A big investment bank bundling custody, clearing, financing, and securities lending for a hedge fund. The fund\'s operational backbone — and its biggest counterparty.' },
  { term: 'Underwriter', aliases: ['garant d\'émission', 'souscripteur (émission)', 'underwriter'], category: 'institutions', def: 'The bank that guarantees an issuer can raise capital, taking the risk of placing the securities. The intermediary that turns a company\'s need for money into marketable securities.' },
  { term: 'Sell-Side', aliases: ['sell side', 'côté vendeur'], category: 'institutions', def: 'Banks and brokers that sell research, execution, and underwriting to clients (the buy-side). They make markets; the buy-side invests.' },
  { term: 'Buy-Side', aliases: ['buy side', 'côté acheteur'], category: 'institutions', def: 'Asset managers, funds, and institutions that buy securities to invest client money. The side that allocates capital; the sell-side serves them.' },
  { term: 'Regulator', aliases: ['régulateur', 'autorité de contrôle', 'amf', 'sec', 'fca'], category: 'institutions', def: 'The authority overseeing markets and firms (AMF in France, SEC in the US, FCA in the UK). Sets the rules that protect clients, markets, and the system from abuse and excess.' },
  { term: 'Systemic Risk', aliases: ['risque systémique', 'systemic risk'], category: 'institutions', def: 'The risk that one failure cascades through the whole system. Why some firms are "too big to fail" and why regulators demand capital, clearing, and resolution plans.' },
  { term: 'Too Big to Fail', aliases: ['trop grand pour faire faillite', 'too big to fail', 'tbtf'], category: 'institutions', def: 'A firm whose collapse would threaten the whole system, so it must be rescued. The moral-hazard problem regulators try to solve with capital rules and resolution plans.' },

  /* ---------------- DERIVATIVES & TRADING ---------------- */
  { term: 'Derivative', aliases: ['dérivé', 'produit dérivé', 'instrument dérivé', 'derivative'], category: 'derivatives', def: 'A contract whose value derives from an underlying asset (rate, price, index). Lets you gain or shed exposure without buying the underlying — flexible, leveraged, and bilateral.' },
  { term: 'Swap', aliases: ['swap', 'échange de flux', 'contrat d\'échange'], category: 'derivatives', conceptId: 'swap', def: 'A derivative where two parties exchange cash flows — most often fixed for floating. The most-used derivative you\'ve never heard of; converts exposures without touching the underlying.' },
  { term: 'Interest Rate Swap', aliases: ['swap de taux', 'irs', 'swap de taux d\'intérêt'], category: 'derivatives', conceptId: 'swap', def: 'Exchanging a fixed for a floating rate on a notional amount — the benchmark swap. Used to convert a floating-rate loan into an effective fixed-rate one (or vice versa).' },
  { term: 'Currency Swap', aliases: ['swap de change', 'swap de devises', 'currency swap'], category: 'derivatives', def: 'Exchanging principal and interest in two currencies. Lets firms borrow cheaply abroad and swap into their home currency — or hedge foreign cash flows.' },
  { term: 'Credit Default Swap', aliases: ['cds', 'swap de défaut', 'credit default swap', 'couverture de défaut'], category: 'derivatives', def: 'A swap that pays out if a named borrower defaults — default insurance on a bond. The buyer pays premiums; the seller pays if the credit goes bad.' },
  { term: 'Future', aliases: ['future', 'contrat à terme', 'contrat futur', 'futures'], category: 'derivatives', conceptId: 'futures', def: 'A standardized, exchange-traded contract to buy or sell at a set price on a future date. Cleared and margined daily — no counterparty risk, but margin calls can force you out.' },
  { term: 'Forward', aliases: ['forward', 'contrat forward', 'contrat à terme de gré à gré'], category: 'derivatives', conceptId: 'forward', def: 'A private, customized contract to buy or sell at a set price on a future date, settled once at maturity. Flexible but bilateral — full counterparty risk, no daily margin.' },
  { term: 'Option', aliases: ['option', 'option négociable'], category: 'derivatives', conceptId: 'options', def: 'The right (not obligation) to buy (call) or sell (put) at a set price by a set date, for a premium. Asymmetric — buyer\'s max loss is the premium; the seller\'s can be far larger.' },
  { term: 'Call Option', aliases: ['option d\'achat', 'call', 'option call'], category: 'derivatives', conceptId: 'options', def: 'The right to buy an asset at the strike price by expiry. Bought to bet on a rise or to cap a purchase price; sold to earn premium income.' },
  { term: 'Put Option', aliases: ['option de vente', 'put', 'option put'], category: 'derivatives', conceptId: 'options', def: 'The right to sell an asset at the strike price by expiry. Bought as insurance against a fall; the most you can lose is the premium paid.' },
  { term: 'Strike Price', aliases: ['prix d\'exercice', 'prix frappé', 'strike', 'prix de référence'], category: 'derivatives', conceptId: 'options', def: 'The locked price at which an option can be exercised. Determines intrinsic value — a call is "in the money" when the stock is above the strike.' },
  { term: 'Premium', aliases: ['prime (option)', 'premium', 'prime d\'option'], category: 'derivatives', conceptId: 'options', def: 'The price paid for an option — the buyer\'s maximum loss. Made of intrinsic value plus time value; rises with volatility and time.' },
  { term: 'Implied Volatility', aliases: ['volatilité implicite', 'implied vol', 'iv'], category: 'derivatives', conceptId: 'options', def: 'The future volatility embedded in an option\'s market price. What option traders really trade — higher IV means pricier options, regardless of direction.' },
  { term: 'VIX', aliases: ['vix', 'indice de volatilité', 'indice de la peur', 'volatility index'], category: 'derivatives', conceptId: 'volatility', def: 'The Volatility Index — implied volatility of S&P 500 options, the market\'s "fear gauge." Spikes in crises; tradable in its own right.' },
  { term: 'Theta', aliases: ['théta', 'theta', 'dépréciation temporelle'], category: 'derivatives', conceptId: 'options', def: 'Time decay — how much value an option bleeds each day it doesn\'t move in the money. The option buyer\'s silent enemy, the seller\'s steady income.' },
  { term: 'Delta', aliases: ['delta', 'sensibilité au cours'], category: 'derivatives', conceptId: 'options', def: 'How much an option\'s price moves per €1 in the underlying. A delta of 0.5 means the option gains ~€0.50 for a €1 rise in the stock.' },
  { term: 'Gamma', aliases: ['gamma'], category: 'derivatives', def: 'How fast delta itself changes as the underlying moves. Matters most near the strike and expiry — the "convexity" that makes options explode at the extremes.' },
  { term: 'Black-Scholes', aliases: ['black scholes', 'black-scholes-merton', 'formule black scholes'], category: 'derivatives', conceptId: 'options', def: 'The closed-form formula pricing a European option from spot, strike, time, rates, and volatility. Famous, Nobel-winning — and built on assumptions (lognormal, constant vol) markets routinely break.' },
  { term: 'Greeks', aliases: ['grecques', 'the greeks', 'paramètres grecs'], category: 'derivatives', def: 'The risk measures of an option book — delta, gamma, theta, vega, rho. The language traders use to manage exposure to each pricing factor.' },
  { term: 'Margin', aliases: ['marge', 'dépôt de garantie', 'margin'], category: 'derivatives', conceptId: 'margin-trading', def: 'Collateral posted to guarantee a leveraged or derivative position. Margin calls force top-ups or liquidation — how leverage becomes ruin.' },
  { term: 'Margin Call', aliases: ['appel de marge', 'margin call', 'mise en demeure de couverture'], category: 'derivatives', conceptId: 'margin-trading', def: 'A demand to add funds when losses push margin below the required level. Unmet, it triggers auto-liquidation — turning a temporary dip into a permanent loss.' },
  { term: 'Initial Margin', aliases: ['marge initiale', 'initial margin'], category: 'derivatives', conceptId: 'margin-trading', def: 'The minimum cash required to open a leveraged position. Sets the maximum leverage; smaller means more leverage and more risk.' },
  { term: 'Maintenance Margin', aliases: ['marge de maintenance', 'maintenance margin'], category: 'derivatives', conceptId: 'margin-trading', def: 'The minimum equity you must keep holding a position. Fall below it and a margin call fires — the tripwire for liquidation.' },
  { term: 'Short Selling', aliases: ['vente à découvert', 'short selling', 'shorter', 'short'], category: 'derivatives', conceptId: 'short-selling', def: 'Selling a borrowed asset in the hope its price falls, so you buy it back cheaper. Profit capped at the original price; loss theoretically unlimited — and squeezes compound it.' },
  { term: 'Borrow Fee', aliases: ['frais d\'emprunt', 'borrow fee', 'frais de prêt'], category: 'derivatives', conceptId: 'short-selling', def: 'The cost of borrowing shares to short. High for "hard-to-borrow" stocks — a real cost that eats short returns, on top of any dividends owed.' },
  { term: 'Naked Short', aliases: ['vente à découvert nue', 'naked short', 'short à nu'], category: 'derivatives', def: 'Short selling without first arranging to borrow the shares. Restricted or banned in most markets — it can create more short exposure than real shares exist.' },
  { term: 'Notional', aliases: ['notionnel', 'montant notionnel', 'nominal'], category: 'derivatives', conceptId: 'swap', def: 'The reference amount used to calculate derivative payments — not actually exchanged. The huge notional figures in derivatives markets overstate the real economic exposure.' },
  { term: 'OTC', aliases: ['gré à gré', 'over the counter', 'otc', 'de gré à gré'], category: 'derivatives', conceptId: 'counterparty', def: 'Over-the-counter — trades negotiated directly between two parties, not on an exchange. Flexible and bespoke, but with real bilateral counterparty risk.' },
  { term: 'Leverage Ratio', aliases: ['ratio de levier', 'levier', 'leverage ratio'], category: 'derivatives', conceptId: 'leverage', def: 'Assets controlled per unit of equity — 3× means €3 of assets per €1 of equity. Magnifies returns and losses equally; the multiplier that decides survival.' },
  { term: 'Mark-to-Market', aliases: ['marquage au marché', 'mark to market', 'mtm', 'valorisation au marché'], category: 'derivatives', conceptId: 'futures', def: 'Revaluing a position to the current market price, settling gains and losses in cash. Daily MTM is what makes futures self-collateralizing — and what makes margin calls fire.' },
  { term: 'Collateral', aliases: ['garantie', 'nantissement', 'collateral', 'gage'], category: 'derivatives', conceptId: 'margin-trading', def: 'An asset pledged to secure a loan or derivative obligation. Reduces counterparty risk — if the borrower defaults, the lender seizes the collateral.' },
  { term: 'Netting', aliases: ['compensation', 'netting', 'netting des positions'], category: 'derivatives', conceptId: 'clearing-house', def: 'Offsetting what you owe against what you are owed, settling only the difference. Cuts the cash that needs to move and the credit exposure — the efficiency of clearing.' },
  { term: 'ISDA Master Agreement', aliases: ['convention isda', 'isda', 'isda master agreement'], category: 'derivatives', conceptId: 'counterparty', def: 'The standard contract framework governing most OTC derivatives, including netting and collateral terms. The legal backbone that makes bilateral derivative risk manageable.' },

  /* ---------------- FINTECH & CRYPTO (new category) ---------------- */
  { term: 'Cryptocurrency', aliases: ['cryptomonnaie', 'crypto', 'cryptocurrency', 'bitcoin', 'jeton numérique'], category: 'fintech', conceptId: 'cryptocurrency', def: 'A digital asset secured by cryptography on a distributed ledger, with no central issuer. Bitcoin is the original; thousands follow — volatile, speculative, and unbacked by cash flows.' },
  { term: 'Bitcoin', aliases: ['bitcoin', 'btc'], category: 'fintech', conceptId: 'cryptocurrency', def: 'The first cryptocurrency: a fixed-supply digital token on a public ledger, created by "mining." Treated by some as digital gold, by others as a speculative asset with no intrinsic cash flows.' },
  { term: 'Blockchain', aliases: ['blockchain', 'chaîne de blocs', 'registre distribué', 'dlt'], category: 'fintech', conceptId: 'blockchain', def: 'A shared, append-only ledger replicated across many computers, secured by cryptography. The technology under crypto — and increasingly tried for settlement, tokenization, and supply chains.' },
  { term: 'Stablecoin', aliases: ['stablecoin', 'pièce stable', 'jeton stable'], category: 'fintech', def: 'A cryptocurrency pegged to a stable asset, usually the dollar. A bridge between crypto volatility and everyday value — its credibility rests entirely on the quality of its reserves.' },
  { term: 'DeFi', aliases: ['defi', 'finance décentralisée', 'decentralized finance'], category: 'fintech', def: 'Decentralized Finance — lending, trading, and earning via smart contracts instead of intermediaries. Open and fast, but largely unregulated, with smart-contract bugs as a constant tail risk.' },
  { term: 'Smart Contract', aliases: ['contrat intelligent', 'smart contract'], category: 'fintech', def: 'Self-executing code on a blockchain that enforces an agreement automatically. Removes the middleman — but a bug in the code is a bug in the contract, often irreversible.' },
  { term: 'NFT', aliases: ['nft', 'jeton non fongible', 'non fungible token'], category: 'fintech', def: 'Non-Fungible Token — a unique digital token proving ownership of a specific asset (often digital art). "Unique" on-chain doesn\'t mean "valuable" off-chain — most have gone to near-zero.' },
  { term: 'Tokenization', aliases: ['tokenisation', 'jeton', 'token'], category: 'fintech', def: 'Representing a real asset (real estate, bonds, art) as a token on a blockchain. Promises fractional ownership and faster settlement — still early, with real legal and custody questions.' },
  { term: 'Mining', aliases: ['minage', 'mining crypto'], category: 'fintech', def: 'The proof-of-work process that secures Bitcoin by solving cryptographic puzzles for new coins. Energy-intensive by design — the cost of a trustless network.' },
  { term: 'Proof of Stake', aliases: ['preuve d\'enjeu', 'proof of stake', 'pos'], category: 'fintech', def: 'A crypto validation method where participants lock up tokens to secure the network — far less energy than mining. Ethereum\'s shift to PoS cut its energy use by ~99.9%.' },
  { term: 'Wallet', aliases: ['portefeuille crypto', 'wallet', 'portefeuille numérique'], category: 'fintech', def: 'Software (or hardware) that stores the keys controlling crypto. Lose the keys, lose the coins — "not your keys, not your coins" is the unforgiving rule.' },
  { term: 'ICO', aliases: ['ico', 'initial coin offering', 'levée de fonds par jetons'], category: 'fintech', def: 'Initial Coin Offering — selling new tokens to fund a crypto project, akin to an IPO but mostly unregulated. Many were pure speculation or outright scams; investors had little recourse.' },
  { term: 'CBDC', aliases: ['cbdc', 'monnaie numérique de banque centrale', 'digital euro', 'monnaie digitale de banque centrale'], category: 'fintech', def: 'Central Bank Digital Currency — a digital form of sovereign money issued directly by the central bank. Programmable and traceable; raises privacy and bank-disintermediation questions.' },
  { term: 'Fintech', aliases: ['fintech', 'technologie financière', 'finance tech'], category: 'fintech', def: 'Technology-driven financial services — payments, lending, investing, banking delivered via software. Reshaping access and cost; the regulatory frontier of modern finance.' },
  { term: 'Open Banking', aliases: ['banque ouverte', 'open banking', 'psd2'], category: 'fintech', def: 'Letting third parties access your bank data (with consent) to offer services. Breaks the bank\'s data monopoly — more competition, more convenience, new privacy considerations.' },
  { term: 'Neobank', aliases: ['néobanque', 'challenger bank', 'banque en ligne'], category: 'fintech', def: 'A digital-only bank without physical branches. Lower costs, slicker apps — but often narrower services and, until licensed, your deposits may sit at a partner bank.' },

  /* ---------------- FOREIGN EXCHANGE ---------------- */
  { term: 'Foreign Exchange', aliases: ['devises', 'forex', 'fx', 'marché des changes', 'change'], category: 'markets', def: 'The market where currencies are traded against each other. The largest, most liquid market on Earth — trillions change hands daily, mostly between banks.' },
  { term: 'Exchange Rate', aliases: ['taux de change', 'cours de change', 'parité monétaire'], category: 'economics', def: 'The price of one currency expressed in another. It moves on interest-rate gaps, trade flows, capital flows, and central-bank policy.' },
  { term: 'Currency Pair', aliases: ['paire de devises', 'parité (forex)'], category: 'markets', def: 'Two currencies quoted together, like EUR/USD. The first is the base, the second the quote; the rate is how much of the quote buys one unit of the base.' },
  { term: 'Pip', aliases: ['pip', 'point (forex)'], category: 'markets', def: 'The smallest usual price move in a forex quote — typically the fourth decimal (0.0001). Spreads and profits are counted in pips.' },
  { term: 'Spot FX', aliases: ['change au comptant', 'spot devises'], category: 'markets', def: 'A foreign-exchange trade settled in one or two days at the current rate. The "cash" leg of the currency market, versus forwards which settle later.' },
  { term: 'Carry Trade', aliases: ['carry trade', 'opération de report'], category: 'markets', def: 'Borrowing in a low-rate currency to invest in a higher-rate one, pocketing the rate gap. Profitable until the funding currency rises or the high-rate one falls.' },
  { term: 'Currency Peg', aliases: ['parité fixe', 'peg', 'ancrage'], category: 'economics', def: 'A fixed exchange rate where a currency is tied to another (often the dollar or euro). Requires reserves to defend — and breaks spectacularly when they run out.' },
  { term: 'Devaluation', aliases: ['dévaluation'], category: 'economics', def: 'A deliberate, official lowering of a currency peg. Makes exports cheaper and imports dearer, and slashes the real value of domestic savings.' },
  { term: 'Revaluation', aliases: ['réévaluation (change)'], category: 'economics', def: 'An official upward reset of a pegged currency. Rarer than devaluation; makes imports cheaper and exports costlier.' },
  { term: 'Reserve Currency', aliases: ['monnaie de réserve'], category: 'economics', def: 'A currency central banks hold in bulk for trade and reserves — the dollar dominates. Its issuer enjoys cheaper borrowing and geopolitical power.' },
  { term: 'Cross Rate', aliases: ['cours croisé', 'taux croisé'], category: 'markets', def: 'An exchange rate between two currencies computed via a common third (often the dollar) when no direct market exists. e.g. EUR/CHF derived from EUR/USD and USD/CHF.' },
  { term: 'Currency Crisis', aliases: ['crise de change', 'attaque spéculative'], category: 'economics', def: 'A sharp loss of confidence in a currency, often ending a peg. Speculators bet against it, reserves drain, and the currency is forced to float and plunge.' },
  { term: 'Eurodollar', aliases: ['eurodollar'], category: 'banking', def: 'US dollar deposits held outside the United States. A huge offshore market that banks use to fund themselves, beyond direct Fed control.' },
  { term: 'Dollarization', aliases: ['dollarisation'], category: 'economics', def: 'A country adopting the US dollar (or another currency) as its own, usually after a local-currency collapse. Kills money-printing risk but loses monetary sovereignty.' },
  { term: 'Currency Board', aliases: ['currency board', 'caisse de conversion'], category: 'economics', def: 'A monetary regime that issues domestic currency only against foreign reserves at a fixed rate. The strictest form of peg — credible because it cannot print.' },
  { term: 'Forward FX', aliases: ['change à terme'], category: 'derivatives', conceptId: 'forward', def: 'A contract locking today an exchange rate for a future date. Lets exporters and importers remove currency risk on a known future payment.' },
  { term: 'Triangular Arbitrage', aliases: ['arbitrage triangulaire'], category: 'markets', def: 'Exploiting a mispricing among three currencies by going around the triangle (USD→EUR→GBP→USD). A textbook arbitrage that algorithms erase in milliseconds.' },

  /* ---------------- COMMODITIES ---------------- */
  { term: 'Commodity', aliases: ['matière première', 'commodity', 'commodities'], category: 'markets', def: 'A raw physical good traded in bulk — oil, gold, wheat, copper. Standardized grades, priced globally, driven by supply and demand shocks.' },
  { term: 'Spot Price', aliases: ['prix au comptant', 'spot'], category: 'markets', def: 'The price for immediate delivery of a commodity or asset. The cash market, versus futures which price delivery later.' },
  { term: 'Brent', aliases: ['brent', 'pétrole brent'], category: 'markets', def: 'The benchmark North Sea crude oil price, the global reference for two-thirds of oil trades. Its price moves on supply, OPEC, and geopolitics.' },
  { term: 'WTI', aliases: ['wti', 'west texas intermediate'], category: 'markets', def: 'The US benchmark crude oil price, traded at Cushing, Oklahoma. Slightly lighter and sweeter than Brent; the two usually trade within a few dollars.' },
  { term: 'Crude Oil', aliases: ['pétrole brut'], category: 'markets', def: 'Unrefined petroleum, the most-traded commodity and a swing factor for inflation and growth. Refined into fuel, plastics, and chemicals.' },
  { term: 'Natural Gas', aliases: ['gaz naturel'], category: 'markets', def: 'A traded energy commodity, notoriously volatile because it is costly to store and transport. Regional prices (US, Europe, Asia) diverge widely.' },
  { term: 'Gold', aliases: ['or', 'métal jaune'], category: 'markets', def: 'A precious metal held as a store of value and safe haven in crises. Pays no income, so its price rises when real rates fall and confidence erodes.' },
  { term: 'Silver', aliases: ['argent métal'], category: 'markets', def: 'A precious and industrial metal — both a safe haven and an input to electronics and solar panels. More volatile than gold for its dual role.' },
  { term: 'Copper', aliases: ['cuivre'], category: 'markets', def: 'An industrial metal so tied to growth it is called "Dr. Copper." Its price is a real-time read on construction and manufacturing demand.' },
  { term: 'Precious Metal', aliases: ['métal précieux'], category: 'markets', def: 'A rare, durable metal valued for preservation of wealth — gold, silver, platinum, palladium. Held as hedges against inflation and crisis.' },
  { term: 'Industrial Metal', aliases: ['métal industriel'], category: 'markets', def: 'A metal used mainly in production — copper, aluminum, zinc, nickel. Prices track the industrial cycle and infrastructure demand.' },
  { term: 'ETC', aliases: ['etc', 'exchange traded commodity'], category: 'markets', def: 'A fund that tracks a commodity or basket and trades like a stock. Gives exposure to oil, gold, or agriculture without handling the physical stuff.' },
  { term: 'Soft Commodities', aliases: ['soft commodities', 'matières premières agricoles'], category: 'markets', def: 'Grown rather than mined goods — coffee, cocoa, sugar, wheat, cotton. Weather and harvest cycles drive sharp, seasonal price swings.' },
  { term: 'Commodity Index', aliases: ['indice matières premières'], category: 'markets', def: 'A basket tracking a range of commodities (S&P GSCI, Bloomberg). Used as an inflation hedge and a diversified bet on real assets.' },
  { term: 'Producer Hedging', aliases: ['couverture producteur'], category: 'derivatives', conceptId: 'hedging', def: 'A miner, farmer, or oil firm using futures to lock the price of what it will later sell. Turns an unpredictable revenue into a known one.' },

  /* ---------------- FIXED INCOME (deep) ---------------- */
  { term: 'Treasury Bill', aliases: ['bon du trésor', 't-bill', 'bta'], category: 'banking', def: 'Short-term government debt (under a year) sold at a discount, paying no coupon. The closest thing to a risk-free cash instrument.' },
  { term: 'Treasury Note', aliases: ['t-note'], category: 'banking', def: 'US government debt of two to ten years, paying a coupon. A core holding in fixed-income portfolios and a global risk benchmark.' },
  { term: 'Treasury Bond', aliases: ['t-bond'], category: 'banking', def: 'Long-term US government debt (twenty or thirty years), paying a coupon. The longest, most rate-sensitive sovereign security.' },
  { term: 'Bund', aliases: ['bund', 'obligation allemande'], category: 'banking', def: 'German government bonds, the eurozone safe benchmark. Their yield is the risk-free rate for the euro area.' },
  { term: 'Gilt', aliases: ['gilt', 'obligation britannique'], category: 'banking', def: 'UK government bonds. The name comes from their original paper having gilded edges; they remain the sterling risk-free benchmark.' },
  { term: 'OAT', aliases: ['oat', 'obligation assimilable du trésor'], category: 'banking', def: 'French government bonds, the main French sovereign benchmark. Their yield tracks eurozone rate expectations and French credit quality.' },
  { term: 'Commercial Paper', aliases: ['papier commercial', 'tcn'], category: 'banking', def: 'Very short-term unsecured debt issued by companies to fund working capital. Cheaper than bank loans for blue-chip issuers, but rolls off quickly.' },
  { term: 'Money Market', aliases: ['marché monétaire'], category: 'banking', def: 'The market for short-term borrowing and lending (overnight to a year) — repos, T-bills, commercial paper. Where the central bank rate actually transmits.' },
  { term: 'Zero-Coupon Bond', aliases: ['obligation zéro coupon', 'zéro coupon'], category: 'banking', def: 'A bond paying no periodic interest, issued at a deep discount and redeemed at face value. The cleanest measure of the time value of money.' },
  { term: 'Inflation-Linked Bond', aliases: ['obligation indexée inflation', 'oati', 'tips'], category: 'banking', def: 'A bond whose principal and coupons rise with inflation, protecting purchasing power. The real-asset hedge within fixed income.' },
  { term: 'Convertible Bond', aliases: ['obligation convertible', 'convertible'], category: 'banking', def: 'A bond that can convert into the issuer stock at a set price — bond downside with equity upside. Cheaper funding for firms, equity option for buyers.' },
  { term: 'Callable Bond', aliases: ['obligation remboursable par anticipation', 'callable'], category: 'banking', def: 'A bond the issuer can repay early if rates fall. Good for the issuer, bad for the holder, who gets reinvestment risk — so it pays a higher yield.' },
  { term: 'Floating Rate Note', aliases: ['floater', 'obligation à taux variable', 'frn'], category: 'banking', def: 'A bond whose coupon resets with a short rate, so its price barely moves when rates change. The natural hedge against rising rates.' },
  { term: 'Convexity', aliases: ['convexité'], category: 'banking', def: 'The curvature of a bond price-yield curve — how duration itself changes as rates move. Positive convexity is good for holders; callable bonds have negative convexity.' },
  { term: 'Current Yield', aliases: ['rendement courant'], category: 'banking', def: 'Annual coupon divided by the current price — the simple income return, ignoring the path to maturity. A quick yield read, less rigorous than YTM.' },
  { term: 'Investment Grade', aliases: ['investment grade', 'notation ig'], category: 'banking', def: 'Bonds rated BBB-/Baa3 or above — considered safe enough for most institutional mandates. Lower yields than high-yield, far lower default risk.' },
  { term: 'Default', aliases: ['défaut', 'défaut de paiement'], category: 'risk', def: 'A borrower failing to pay interest or principal on time. The core event in credit risk; it triggers recovery, restructuring, or bankruptcy.' },
  { term: 'Recovery Rate', aliases: ['taux de recouvrement'], category: 'risk', def: 'The fraction of a bond or loan recovered after a default, through collateral or restructuring. The complement of loss given default; higher for secured debt.' },
  { term: 'Covenant', aliases: ['convenant', 'pacte'], category: 'banking', def: 'A contractual rule a borrower must follow (keep ratios above floors, limit debt). Breaching it triggers early repayment — a creditor protection.' },
  { term: 'Indenture', aliases: ['indenture', 'contrat obligataire'], category: 'banking', def: 'The legal contract of a bond, setting coupon, maturity, covenants, and remedies. The rulebook that binds the issuer and protects holders.' },
  { term: 'Trustee', aliases: ['fiduciaire (obligation)', 'trustee'], category: 'institutions', def: 'An independent party that enforces bond terms on behalf of holders. Acts if the issuer breaches covenants, so dispersed investors have a voice.' },
  { term: 'Credit Downgrade', aliases: ['dégradation de notation', 'downgrade'], category: 'banking', def: 'A ratings agency lowering a borrower grade, raising its borrowing cost and often its bond spreads. Forced selling often follows when mandates forbid lower-rated paper.' },
  { term: 'Sovereign Spread', aliases: ['spread souverain'], category: 'banking', def: 'The extra yield a country pays over the safest sovereign (German Bunds in the euro area). Widens with fiscal or political risk — a national stress gauge.' },
  { term: 'STRIP', aliases: ['strip', 'obligation démembrée'], category: 'banking', def: 'A bond split into its coupon and principal pieces, each traded separately as zero-coupons. Lets investors match exact cash-flow dates.' },

  /* ---------------- DERIVATIVES (advanced) ---------------- */
  { term: 'Exotic Option', aliases: ['option exotique'], category: 'derivatives', def: 'A non-standard option with features beyond vanilla calls/puts — barriers, lookbacks, digitals. Cheaper, tailored, but harder to value and hedge.' },
  { term: 'Barrier Option', aliases: ['option à barrière', 'barrière'], category: 'derivatives', def: 'An option that activates or vanishes only if the price crosses a barrier. Cheaper than vanilla because the knockout risk may cancel the payout.' },
  { term: 'Asian Option', aliases: ['option asiatique'], category: 'derivatives', def: 'An option settling on the average price over a period, not the final price. Smoother and cheaper — hard to manipulate against a single date.' },
  { term: 'Bermudan Option', aliases: ['option bermudienne'], category: 'derivatives', def: 'An option exercisable on specific dates before expiry — between American (anytime) and European (only at expiry). Flexibility at a middle price.' },
  { term: 'Straddle', aliases: ['straddle', 'achat double'], category: 'derivatives', def: 'Buying a call and a put at the same strike. Profits if the asset moves a lot either way; loses if it sits still. A pure bet on volatility.' },
  { term: 'Strangle', aliases: ['strangle'], category: 'derivatives', def: 'Like a straddle but with out-of-the-money call and put. Cheaper to enter, needs a bigger move to profit — same volatility bet, wider break-evens.' },
  { term: 'Iron Condor', aliases: ['iron condor', 'condor en fer'], category: 'derivatives', def: 'A four-leg option structure that profits if the asset stays in a range. Sells volatility on both sides for capped risk and capped reward.' },
  { term: 'Butterfly', aliases: ['papillon', 'butterfly'], category: 'derivatives', def: 'A three-strike spread betting the price lands near the middle and away from the wings. Low cost, high payoff if right, total premium loss if wrong.' },
  { term: 'Collar', aliases: ['collar', 'collier'], category: 'derivatives', def: 'Owning an asset, buying a put for downside protection and selling a call to fund it. Caps upside to finance a floor — zero-cost hedging.' },
  { term: 'Covered Call', aliases: ['covered call', 'achat couvert'], category: 'derivatives', def: 'Holding a stock and selling a call on it. Earns premium income but caps upside — the stock can be called away if it rises past the strike.' },
  { term: 'Protective Put', aliases: ['protective put', 'put de protection'], category: 'derivatives', conceptId: 'options', def: 'Holding a stock and buying a put as insurance. Pays a premium to cap the downside while keeping the upside — portfolio insurance.' },
  { term: 'Calendar Spread', aliases: ['écart calendaire', 'calendar spread'], category: 'derivatives', def: 'Buying and selling options of the same strike but different expiries. Bets on how time value decays across maturities rather than on direction.' },
  { term: 'Vertical Spread', aliases: ['écart vertical', 'vertical spread'], category: 'derivatives', def: 'Buying and selling options of the same expiry but different strikes. A cheaper, capped directional bet than a naked option.' },
  { term: 'Delta Hedging', aliases: ['couverture delta', 'delta hedging'], category: 'derivatives', conceptId: 'options', def: 'Adjusting a position so its net delta is zero, isolating volatility from direction. The daily work of option market makers — constant rebalancing.' },
  { term: 'Vega', aliases: ['véga'], category: 'derivatives', def: 'How much an option price moves per 1% change in implied volatility. Long options are long vega — they gain when vol rises, lose when it falls.' },
  { term: 'Rho', aliases: ['rho'], category: 'derivatives', def: 'How much an option price moves per 1% change in interest rates. Usually small except on long-dated options — the least-watched of the Greeks.' },
  { term: 'Volatility Skew', aliases: ['smile de volatilité', 'skew de vol'], category: 'derivatives', conceptId: 'options', def: 'The pattern of implied volatility across strikes — typically low strikes carry higher vol. Reveals the market prices crashes more than rallies.' },
  { term: 'Volatility Smile', aliases: ['sourire de volatilité'], category: 'derivatives', def: 'A U-shaped implied-vol curve across strikes, higher at both wings than at the money. Tells you the market assigns real probability to big moves in either direction.' },
  { term: 'Variance Swap', aliases: ['swap de variance'], category: 'derivatives', def: 'A contract paying the difference between realized and implied variance — a pure trade on realized volatility, no delta to manage.' },
  { term: 'Open Interest', aliases: ['intérêt ouvert', 'open interest'], category: 'derivatives', def: 'The number of derivative contracts still live (not closed or settled). Rising open interest with price confirms a trend; falling hints it is unwinding.' },
  { term: 'Option Chain', aliases: ['option chain', 'liste options'], category: 'derivatives', def: 'The full list of strikes and expiries for a given underlying. The option trader menu, showing prices, Greeks, and open interest at each point.' },
  { term: 'Volatility Term Structure', aliases: ['structure par terme (vol)'], category: 'derivatives', def: 'Implied volatility across option expiries. Usually upward-sloping in calm, but inverted when the market fears a near-term shock.' },

  /* ---------------- STRUCTURED PRODUCTS ---------------- */
  { term: 'Structured Note', aliases: ['note structurée'], category: 'banking', def: 'A bond whose payoff depends on an embedded derivative — linked to a stock, index, rate, or basket. Tailored risk/return, but opaque and hard to value.' },
  { term: 'Certificate', aliases: ['certificat'], category: 'banking', def: 'An exchange-traded note tracking an index or strategy, sometimes with leverage or capital protection. A simple wrapper, transparent price, issuer credit risk.' },
  { term: 'Autocallable', aliases: ['autocallable', 'autocall'], category: 'banking', def: 'A structured note that redeems early if a condition is met (the underlying above a barrier on observation dates). Higher coupon for the early-exit risk.' },
  { term: 'Reverse Convertible', aliases: ['reverse convertible'], category: 'banking', def: 'A note paying a high coupon, but if the underlying drops, you get paid in depressed stock instead of cash. Selling a put to buy income — risky income.' },
  { term: 'Capital-Guaranteed Product', aliases: ['capital garanti', 'produit capital garanti'], category: 'banking', def: 'A note protecting principal while offering some upside exposure. The safety costs you — the upside is capped and participation is partial.' },
  { term: 'ELN', aliases: ['eln', 'equity linked note'], category: 'banking', def: 'A note whose payoff depends on a single stock or basket. Debt with equity-like returns; popular for income or customized exposure.' },

  /* ---------------- INSURANCE & ACTUARIAL ---------------- */
  { term: 'Insurance Premium', aliases: ['prime assurance', 'prime'], category: 'personal', def: 'The price you pay for insurance cover, set from risk and pooled losses. The smaller, certain cost that avoids the larger, uncertain one.' },
  { term: 'Deductible', aliases: ['franchise', 'deductible'], category: 'personal', def: 'The amount you pay yourself before insurance kicks in. Higher deductible lowers the premium — you self-insure the small losses.' },
  { term: 'Policyholder', aliases: ['souscripteur', 'assuré'], category: 'personal', def: 'The person who owns the insurance contract and pays the premium. Distinct from the insured (whose life is covered) and the beneficiary (who receives the payout).' },
  { term: 'Insurer', aliases: ['assureur', 'compagnie assurance'], category: 'institutions', def: 'A firm that pools premiums to pay the losses of the few. Profits from pricing risk and investing the float — the cash it holds before claims come due.' },
  { term: 'Reinsurance', aliases: ['réassurance'], category: 'institutions', def: 'Insurance for insurers — transferring some risk to a reinsurer. Lets primary insurers write more business and survive the catastrophic event they could not bear alone.' },
  { term: 'Reinsurer', aliases: ['réassureur'], category: 'institutions', def: 'A firm that takes on risks from primary insurers, globally diversified. The backstop of the insurance system — Munich Re, Swiss Re, Lloyd syndicates.' },
  { term: 'Underwriting (Insurance)', aliases: ['souscription (assurance)', 'tarification'], category: 'institutions', def: 'Selecting and pricing the risks an insurer will take. Good underwriting is the whole game — pricing risk above expected loss, and declining the bad risks.' },
  { term: 'Life Insurance', aliases: ['assurance vie', 'assurance décès'], category: 'personal', def: 'Cover paying out on death, protecting dependants from lost income. Term cover is pure protection; whole-life wraps a savings element and costs far more.' },
  { term: 'Annuity', aliases: ['rente', 'annuité'], category: 'personal', def: 'A contract paying a stream of income for life or a fixed term. Converts a lump sum into a pension, transferring longevity risk to the insurer.' },
  { term: 'Term Life', aliases: ['assurance temporaire décès'], category: 'personal', def: 'Pure death cover for a set period, no savings element. The cheapest way to protect a family while dependants are young and debts are high.' },
  { term: 'Actuary', aliases: ['actuaire'], category: 'institutions', def: 'A professional who prices risk with probability and statistics — the math behind insurance and pensions. Turning uncertainty into a premium number.' },
  { term: 'Adverse Selection', aliases: ['antisélection', 'sélection adverse'], category: 'risk', def: 'When the riskiest customers are most eager to buy cover, driving prices up and healthy ones out. Why insurers ask medical questions and mandate enrolment.' },
  { term: 'Loss Ratio', aliases: ['ratio de sinistralité', 'loss ratio'], category: 'institutions', def: 'Claims paid divided by premiums earned. The core measure of underwriting — a ratio above 100% means paying out more than you collect.' },
  { term: 'Combined Ratio', aliases: ['ratio combiné', 'combined ratio'], category: 'institutions', def: 'Losses plus expenses divided by premiums. Below 100% the insurer profits from underwriting alone; above it, only investment income keeps it alive.' },
  { term: 'Loss Reserves', aliases: ['provisions pour sinistres'], category: 'institutions', def: 'Money set aside for claims not yet reported or settled. The judgment call that defines insurer solvency — under-reserving surfaces as a later surprise loss.' },
  { term: 'Solvency', aliases: ['solvabilité (assurance)'], category: 'institutions', def: 'An insurer holding enough capital to meet all plausible claims. Regulators require it; the failure mode is under-reserving eating the capital base.' },

  /* ---------------- TAX & FISCALITY ---------------- */
  { term: 'Capital Gains Tax', aliases: ['impôt sur plus value', 'capital gains tax', 'imposition plus value'], category: 'personal', def: 'Tax on the profit from selling an asset above its purchase price. Often lower than income tax to encourage investment; long-held gains may be taxed less.' },
  { term: 'Income Tax', aliases: ['impôt sur le revenu'], category: 'personal', def: 'Tax on earnings, usually progressive — higher brackets pay a higher rate. The main source of government revenue in most countries.' },
  { term: 'Wealth Tax', aliases: ['impôt sur la fortune', 'isf', 'impôt fortune'], category: 'personal', def: 'A yearly tax on net assets above a threshold. Rare globally; debated for its effect on capital flight and on assets that are illiquid but high-value.' },
  { term: 'Tax Bracket', aliases: ['tranche imposable', 'tranche'], category: 'personal', def: 'A band of income taxed at a given rate in a progressive system. Marginal rate = the rate on your next euro; effective rate = total tax divided by income.' },
  { term: 'Withholding Tax', aliases: ['retenue à la source', 'prélèvement à la source'], category: 'personal', def: 'Tax deducted by the payer before you receive income (dividends, interest, salary). Spreads collection across the year and catches tax residents and non-residents alike.' },
  { term: 'Dividend Tax', aliases: ['imposition dividende'], category: 'personal', def: 'Tax on dividend income, often with a credit for corporate tax already paid. Treated separately from capital gains and usually less favorably than long-term holdings.' },
  { term: 'VAT', aliases: ['tva', 'taxe sur valeur ajoutée'], category: 'economics', def: 'A consumption tax levied at each stage on value added, borne by the final buyer. The main indirect tax in Europe; broad base, low evasion, regressive by nature.' },
  { term: 'Corporate Tax', aliases: ['impôt société', 'is'], category: 'corporate', def: 'Tax on company profits. Deductibility of interest (but not dividends) biases firms toward debt financing — a quirk that shapes capital structure.' },
  { term: 'Tax Haven', aliases: ['paradis fiscal'], category: 'institutions', def: 'A jurisdiction with low or zero tax and weak transparency, used to shift profits. Saves multinationals billions; under global pressure to share information now.' },
  { term: 'Offshore', aliases: ['offshore'], category: 'institutions', def: 'Holding assets or entities in a foreign, often low-tax, jurisdiction. Legitimate for cross-border business; abused for tax avoidance and secrecy.' },
  { term: 'Estate Tax', aliases: ['droits de succession', 'impôt succession'], category: 'personal', def: 'Tax on inherited wealth above a threshold. Debated for fairness and for its effect on family businesses; widely avoided via trusts and life-insurance wrappers.' },
  { term: 'Stamp Duty', aliases: ['droit de timbre', 'droit de mutation'], category: 'markets', def: 'A tax on transactions, often property or share purchases. Raises the cost of trading; in the UK a material cost of home buying.' },
  { term: 'PEA', aliases: ['pea', 'plan épargne actions'], category: 'personal', def: 'A French tax-advantaged account for European equities, exempt from tax after five years. The local vehicle for long-term equity investing.' },
  { term: 'Assurance-Vie', aliases: ['assurance vie (enveloppe)', 'contrat assurance vie'], category: 'personal', def: 'A French life-insurance savings wrapper with major tax and inheritance advantages. The favored long-term savings vehicle in France, despite its name.' },
  { term: 'Livret A', aliases: ['livret a'], category: 'personal', def: 'A French tax-free, regulated savings account with a capped balance. Safe and liquid, but the rate is low and the cap limits its role.' },
  { term: 'LEP', aliases: ['lep', 'livret épargne populaire'], category: 'personal', def: 'A French regulated savings account for modest incomes, paying more than Livret A. Better rate but access-restricted by income.' },

  /* ---------------- MARKET MICROSTRUCTURE ---------------- */
  { term: 'Tick Size', aliases: ['taille de tick', 'pas de cotation'], category: 'markets', def: 'The minimum price increment a quote can move. Too small and orders spam; too large and spreads widen — regulators tune it for liquidity.' },
  { term: 'Level 2', aliases: ['niveau 2', 'carnet approfondi'], category: 'markets', def: 'The full order book showing depth at multiple price levels, not just the best bid/ask. Reveals where real support and resistance are parked.' },
  { term: 'Market Depth', aliases: ['profondeur de marché'], category: 'markets', def: 'The volume available at each price level. Deep markets absorb big orders with little price change; thin ones move sharply on small trades.' },
  { term: 'Best Execution', aliases: ['meilleure exécution'], category: 'markets', def: 'The regulatory duty to get the best available price for a client order. Brokers must route to where price, speed, and likelihood of fill are best overall.' },
  { term: 'Settlement', aliases: ['règlement livraison', 'settlement'], category: 'markets', def: 'The actual exchange of cash for securities after a trade. T+2 means two business days later; failed settlement is the back-office nightmare.' },
  { term: 'T+2', aliases: ['t plus 2', 'règlement t+2'], category: 'markets', def: 'The standard two-business-day lag between a trade and its settlement. Being compressed toward T+1 as technology and instant settlement advance.' },
  { term: 'Novation', aliases: ['novation'], category: 'institutions', def: 'Replacing one party in a contract with a third — how a clearing house inserts itself between buyer and seller, becoming the counterparty to both.' },
  { term: 'Exchange', aliases: ['bourse', 'marché organisé'], category: 'institutions', def: 'A regulated venue matching buyers and sellers under fixed rules. Provides transparency, price discovery, and central counterparty clearing.' },
  { term: 'ATS', aliases: ['ats', 'système de trading alternatif'], category: 'markets', def: 'Alternative Trading System — a matching venue outside the main exchanges, including dark pools. Regulated more lightly than lit exchanges.' },
  { term: 'NBBO', aliases: ['nbbo', 'meilleur prix national'], category: 'markets', def: 'National Best Bid and Offer — the tightest quoted spread across all exchanges in the US. Brokers must generally match or beat it for retail orders.' },
  { term: 'Internalization', aliases: ['internalisation'], category: 'markets', def: 'A broker filling client orders from its own inventory rather than sending them to an exchange. Faster and cheaper, but raises conflict-of-interest questions.' },

  /* ---------------- QUANT & PORTFOLIO ---------------- */
  { term: 'Risk Parity', aliases: ['parité de risque', 'risk parity'], category: 'investing', def: 'Allocating by risk contribution, not capital — each asset class gets the same risk budget. Usually needs leverage on bonds to match stock risk.' },
  { term: 'Tracking Error', aliases: ['erreur de suivi', 'tracking error'], category: 'investing', def: 'How much a portfolio deviates from its benchmark. Low is the goal of index funds; high may reflect active bets or costs.' },
  { term: 'Information Ratio', aliases: ['ratio information', 'information ratio'], category: 'investing', def: 'Active return divided by tracking error — the manager skill per unit of active risk. The active manager scorecard; higher is better.' },
  { term: 'Treynor Ratio', aliases: ['ratio de treynor'], category: 'investing', def: 'Excess return divided by beta, not volatility — return per unit of market risk. Like Sharpe but rewards only systematic risk taken.' },
  { term: 'Jensen Alpha', aliases: ['alpha de jensen'], category: 'investing', def: 'The return above what CAPM predicts for a given beta — risk-adjusted outperformance. Positive alpha means skill (or luck); persistent positive alpha is rare.' },
  { term: 'Backtest', aliases: ['backtest', 'test historique'], category: 'investing', def: 'Running a strategy on past data to see how it would have done. Useful but seductive — the past never includes the strategy affecting prices, and overfitting is rife.' },
  { term: 'Overfitting', aliases: ['surapprentissage', 'overfitting'], category: 'investing', def: 'A model that fits history perfectly by tuning too many parameters, then fails in live trading. The curse of backtests — complexity that memorizes noise.' },
  { term: 'Systematic Investing', aliases: ['systématique', 'investissement systématique'], category: 'investing', def: 'Rules-based investing driven by a model, not human discretion. Repeatable, scalable, and free of emotion — but only as good as the rules.' },
  { term: 'Minimum-Variance Portfolio', aliases: ['variance minimum', 'min variance'], category: 'investing', def: 'The mix of risky assets with the lowest total volatility. The leftmost point of the efficient frontier — lowest risk for the asset class set.' },
  { term: 'Quality Factor', aliases: ['facteur qualité'], category: 'investing', def: 'The empirical tendency of profitable, low-debt, stable companies to outperform. A rewarded factor, alongside value, size, momentum, and low-vol.' },
  { term: 'Size Factor', aliases: ['facteur taille', 'effet taille'], category: 'investing', def: 'The historical tendency of small companies to outperform large ones. A rewarded factor, though its strength has weakened since it was first published.' },
  { term: 'Value Factor', aliases: ['facteur valeur'], category: 'investing', def: 'The tendency of cheap stocks (low P/E, low price-to-book) to outperform dear ones. The oldest rewarded factor; goes through long, painful droughts.' },
  { term: 'Factor Crowding', aliases: ['engorgement de facteur'], category: 'investing', def: 'When too many investors follow the same factor, its advantage shrinks or reverses. The risk that systematic strategies compete away their own edge.' },
  { term: 'Low-Volatility Factor', aliases: ['faible volatilité (facteur)', 'low vol'], category: 'investing', def: 'The anomaly that low-volatility stocks have matched or beaten the market with less risk. A puzzle — theory says higher risk should pay more.' },

  /* ---------------- MACRO ---------------- */
  { term: 'Business Cycle', aliases: ['cycle économique', 'cycle des affaires'], category: 'economics', def: 'The rhythm of expansion, peak, recession, and recovery. Never quite repeats; central banks try to smooth it and investors try to anticipate it.' },
  { term: 'Expansion', aliases: ['expansion', 'phase haussière'], category: 'economics', def: 'The phase of the cycle where output and employment grow. Usually the longest phase; it ends when inflation or excess forces central banks to tighten.' },
  { term: 'Soft Landing', aliases: ['atterrissage en douceur', 'soft landing'], category: 'economics', def: 'A central bank slowing inflation without causing a recession. Rare and hard — the Fed achieved it only a few times in modern history.' },
  { term: 'Hard Landing', aliases: ['atterrissage brutal', 'hard landing'], category: 'economics', def: 'Tightening that kills inflation by triggering recession. The usual alternative when a soft landing proves impossible.' },
  { term: 'Output Gap', aliases: ['écart de production', 'output gap'], category: 'economics', def: 'The difference between actual output and potential. A positive gap means overheating and inflation pressure; negative means slack and disinflation.' },
  { term: 'NAIRU', aliases: ['nairu', 'chômage inflation stable'], category: 'economics', def: 'The unemployment rate below which inflation accelerates. Unobservable and contested, but it frames every central-bank rate decision.' },
  { term: 'Potential Growth', aliases: ['croissance potentielle'], category: 'economics', def: 'The fastest an economy can grow without inflation, set by labor, capital, and productivity. The speed limit that policy cannot safely exceed.' },
  { term: 'Debt-to-GDP', aliases: ['dette pib', 'ratio dette pib'], category: 'economics', def: 'National debt divided by annual output — a capacity-to-repay gauge. Sustainable if growth and inflation outpace interest costs.' },
  { term: 'Balance of Payments', aliases: ['balance des paiements'], category: 'economics', def: 'A full record of a country cross-border flows — current, capital, and financial accounts. Must sum to zero; a deficit on one is funded by the others.' },
  { term: 'Capital Account', aliases: ['compte capital', 'compte financier'], category: 'economics', def: 'The part of the balance of payments tracking investment flows — foreign direct investment, portfolio investment, and reserves.' },
  { term: 'Foreign Direct Investment', aliases: ['ide', 'investissement direct étranger', 'fdi'], category: 'economics', def: 'A lasting investment in a foreign company giving control or influence. Brings capital, jobs, and know-how; less flighty than portfolio flows.' },
  { term: 'Capital Flight', aliases: ['fuite de capitaux'], category: 'economics', def: 'Residents moving money abroad, usually to escape risk, inflation, or a falling currency. A signal of lost confidence that worsens the crisis it flees.' },
  { term: 'Inflation Targeting', aliases: ['cible inflation', 'inflation targeting'], category: 'economics', def: 'A central-bank framework that sets policy to keep inflation near a goal (usually 2%). Clear and credible, used by most major central banks.' },
  { term: 'Forward Guidance', aliases: ['guidage par les taux', 'forward guidance'], category: 'economics', def: 'A central bank signaling future policy to shape market expectations. By telling markets what it will do, it moves long rates without acting.' },
  { term: 'Dot Plot', aliases: ['dot plot', 'diagramme des points'], category: 'economics', def: 'A chart of Fed officials individual rate expectations. Watched intensely, though it is a forecast, not a commitment.' },
  { term: 'Tapering', aliases: ['taper', 'réduction achats'], category: 'economics', def: 'A central bank slowing its asset purchases, the first step toward removing stimulus. Markets often wobble at the mere mention of it.' },
  { term: 'Tightening', aliases: ['resserrement monétaire', 'tightening'], category: 'economics', def: 'A central bank raising rates or draining liquidity to cool inflation. Slows growth, hits asset prices, and strengthens the currency.' },
  { term: 'Easing', aliases: ['assouplissement', 'easing'], category: 'economics', def: 'A central bank cutting rates or buying assets to stimulate. Boosts growth and asset prices; risks inflation and bubbles if overdone.' },

  /* ---------------- BANKING REGULATION ---------------- */
  { term: 'Basel', aliases: ['bâle', 'bâle iii'], category: 'institutions', def: 'Global rules setting how much capital banks must hold. Basel III raised requirements after 2008 to make banks survive stress they failed back then.' },
  { term: 'Capital Adequacy', aliases: ['adéquation des fonds propres'], category: 'institutions', def: 'A bank holding enough capital for its risks. The core prudential ratio — too little capital and a modest loss wipes out depositors.' },
  { term: 'Tier 1 Capital', aliases: ['fonds propres durs', 'tier 1'], category: 'institutions', def: 'The highest-quality bank capital — equity and retained earnings. The buffer that absorbs losses first, keeping the bank alive.' },
  { term: 'Leverage Ratio (Regulatory)', aliases: ['ratio de levier (réglementaire)'], category: 'institutions', def: 'A simple capital divided by total assets, with no risk weighting. A backstop against the risk-weighted ratios being gamed.' },
  { term: 'Liquidity Coverage Ratio', aliases: ['lcr', 'ratio liquidité court terme'], category: 'institutions', def: 'A rule that banks hold enough liquid assets to survive a 30-day stress. Forcing banks to hold liquidity they could lend costs profit, but prevents runs.' },
  { term: 'Net Stable Funding Ratio', aliases: ['nsfr', 'ratio net financement stable'], category: 'institutions', def: 'A rule that long-term assets be funded by stable, not overnight, money. Pushes banks away from the maturity mismatch that sank Northern Rock.' },
  { term: 'Resolution', aliases: ['résolution (banque)', 'plan de résolution'], category: 'institutions', def: 'An orderly plan to wind down a failing bank without a bailout or systemic chaos. The post-2008 answer to too-big-to-fail.' },
  { term: 'Bail-in', aliases: ['bail in', 'sauvetage interne'], category: 'institutions', def: 'Recapitalizing a failing bank by writing down its bondholders and depositors above a cap. Losses borne by investors, not taxpayers — the anti-bailout tool.' },
  { term: 'Ring-Fencing', aliases: ['cloisonnement', 'ring fencing'], category: 'institutions', def: 'Separating a bank retail arm from its investment arm. Protects depositors and payment functions from trading losses on the other side.' },
  { term: 'Volcker Rule', aliases: ['règle volcker'], category: 'institutions', def: 'A US ban on banks doing proprietary trading for their own account. Stops taxpayer-backed deposits funding speculative bets — hard to enforce cleanly.' },
  { term: 'MiFID', aliases: ['mifid', 'mifir'], category: 'institutions', def: 'EU rules for investment services — transparency, best execution, client protection. The rulebook that governs how European brokers and markets operate.' },
  { term: 'EMIR', aliases: ['emir'], category: 'institutions', def: 'EU rules requiring clearing and reporting of derivatives. The European response to the post-2008 push to make the swaps market transparent.' },
  { term: 'AML', aliases: ['lcbft', 'anti blanchiment', 'aml'], category: 'institutions', def: 'Anti-money-laundering rules forcing firms to know clients and report suspicious flows. The cost of keeping finance out of crime; heavy compliance burden.' },
  { term: 'KYC', aliases: ['kyc', 'connaissance client'], category: 'institutions', def: 'Know-Your-Customer checks that identify clients and their risk. The first line of defense against money laundering, fraud, and sanctions breaches.' },
  { term: 'Deposit Insurance', aliases: ['garantie des dépôts', 'assurance dépôts'], category: 'banking', def: 'A guarantee that small depositors are paid if a bank fails. Stops bank runs before they start — the trust that keeps the system liquid.' },
  { term: 'Shadow Banking', aliases: ['shadow banking', 'banque ombre', 'nbfi'], category: 'institutions', def: 'Non-bank financial intermediaries doing bank-like activity — funds, securitization vehicles. A growing share of credit, but outside bank rules and deposit insurance.' },

  /* ---------------- CORPORATE (extended) ---------------- */
  { term: 'Return on Assets', aliases: ['roa', 'rentabilité des actifs'], category: 'corporate', def: 'Net income divided by total assets — profit per unit of assets. A measure of how efficiently a firm uses everything it owns.' },
  { term: 'ROCE', aliases: ['roce', 'rentabilité capitaux employés'], category: 'corporate', def: 'Return on capital employed — profit before financing costs divided by debt plus equity. A clean measure of operational efficiency regardless of funding mix.' },
  { term: 'Economic Profit', aliases: ['profit économique', 'economic value added'], category: 'corporate', def: 'Profit after charging for the cost of all capital — the only true measure of value creation. Positive means earning more than the capital costs.' },
  { term: 'EVA', aliases: ['eva'], category: 'corporate', def: 'Economic Value Added — a trademarked economic-profit metric. Rewarding managers for EVA aligns them with shareholders better than accounting profit alone.' },
  { term: 'Capital Allocation', aliases: ['allocation du capital'], category: 'corporate', def: 'How a CEO deploys cash — reinvest, acquire, buy back, or pay dividends. The most important job of management and the main driver of long-term value.' },
  { term: 'Hurdle Rate', aliases: ['taux de rentabilité minimum', 'taux obstacle'], category: 'corporate', def: 'The minimum return a project must clear to be funded, usually the WACC plus a risk premium. Below it, the project destroys value.' },
  { term: 'IRR', aliases: ['tri', 'taux rentabilité interne'], category: 'corporate', def: 'Internal Rate of Return — the discount rate that makes a project net present value zero. The return of the project itself; accept if it beats the hurdle.' },
  { term: 'NPV', aliases: ['van', 'valeur actuelle nette'], category: 'corporate', def: 'Net Present Value — today value of a project cash flows minus its cost. Positive NPV means the project adds value; this is the gold-standard capital-budgeting rule.' },
  { term: 'Payback Period', aliases: ['délai récupération', 'payback'], category: 'corporate', def: 'How many years until a project returns its initial cost. Simple and intuitive, but ignores cash flows after the payback and the time value of money.' },
  { term: 'Modigliani-Miller', aliases: ['modigliani miller'], category: 'corporate', def: 'The theorem that, in a world without taxes, firm value is independent of its debt-equity mix. Foundational; with taxes, debt gains a tax shield and the picture changes.' },
  { term: 'Stock Split', aliases: ['fractionnement', 'split'], category: 'markets', def: 'Dividing each share into more shares at the same total value. Lowers the price per share to stay tradable; no economic change, often a positive signal.' },
  { term: 'Reverse Split', aliases: ['regroupement', 'reverse split'], category: 'markets', def: 'Combining shares to raise the per-share price, often to avoid delisting. Usually a warning sign — the stock has fallen to a level that embarrasses the exchange.' },
  { term: 'Payout Ratio', aliases: ['taux distribution', 'payout'], category: 'corporate', def: 'The share of earnings paid as dividends. Above 75-80% is often unsustainable; very low means the firm is reinvesting or hoarding cash.' },
  { term: 'Dilution', aliases: ['dilution'], category: 'corporate', def: 'Issuing new shares reduces existing holders stake and per-share metrics. The hidden cost of stock-based compensation and rights issues.' },
  { term: 'Poison Pill', aliases: ['pilule empoisonnée', 'poison pill'], category: 'corporate', def: 'A defense that floods a bidder with cheap shares if it crosses a threshold. Deters hostile takeovers by making them prohibitively expensive.' },
  { term: 'Proxy Vote', aliases: ['vote par procuration', 'proxy'], category: 'corporate', def: 'A shareholder delegating voting rights to a manager or another party. How dispersed owners actually exercise control over a company.' },
  { term: 'Stakeholder', aliases: ['partie prenante', 'stakeholder'], category: 'corporate', def: 'Anyone affected by a firm — employees, customers, suppliers, communities, shareholders. The wider view against shareholder primacy.' },
  { term: 'ESG', aliases: ['esg', 'extra financier', 'environnement social gouvernance'], category: 'investing', def: 'Environmental, Social, and Governance criteria for assessing non-financial risks. Widely used and widely debated for greenwashing and measurement problems.' },
  { term: 'Green Bond', aliases: ['obligation verte'], category: 'banking', def: 'A bond whose proceeds fund environmental projects. Cheaper funding for the issuer and a labeled option for ESG-mandated investors — the label requires reporting.' },
  { term: 'SRI', aliases: ['isr', 'investissement socialement responsable'], category: 'investing', def: 'Socially Responsible Investing — screening for ethical or ESG criteria. Excludes objectionable sectors or tilts toward responsible firms.' },
  { term: 'Impact Investing', aliases: ['investissement impact'], category: 'investing', def: 'Investing to generate measurable social or environmental good alongside a financial return. Intention and measurement are what separate it from ordinary ESG tilts.' },
  { term: 'Stewardship', aliases: ['stewardship', 'engagement actionnarial'], category: 'investing', def: 'Asset managers engaging with companies to improve behavior rather than just selling. Voting and dialogue as tools of responsible ownership.' },
  { term: 'Carbon Credit', aliases: ['crédit carbone', 'quota co2'], category: 'economics', def: 'A permit to emit a tonne of CO2, tradable on a market. Puts a price on emissions; the mechanism behind cap-and-trade systems.' },
  { term: 'Cap and Trade', aliases: ['plafond échange', 'cap and trade'], category: 'economics', def: 'A system capping total emissions and letting firms trade permits. Cuts pollution at least cost, if the cap tightens over time.' },

  /* ---------------- PERSONAL (extended) ---------------- */
  { term: 'Brokerage Account', aliases: ['compte titres', 'compte brokerage'], category: 'personal', def: 'An account holding investments at a broker. The gateway to markets — now often zero-commission, with the cost hidden in execution.' },
  { term: 'Mutual Fund Load', aliases: ['frais entrée (fonds)', 'load'], category: 'personal', def: 'A sales commission on a mutual fund, front or back-end. A cost that goes to the seller, not the investor — best avoided with no-load funds.' },
  { term: 'Wrap Fee', aliases: ['frais enveloppe', 'wrap fee'], category: 'personal', def: 'A single fee covering advice, trading, and custody of a managed portfolio. Predictable, but watch that it does not duplicate fund fees inside.' },
  { term: 'Financial Advisor', aliases: ['conseiller financier'], category: 'institutions', def: 'A professional who builds and manages a financial plan. Best paid a flat fee (fiduciary), not commission — the compensation model predicts the advice quality.' },
  { term: 'Debt-to-Income', aliases: ['dti', 'ratio endettement revenu'], category: 'personal', def: 'Debt payments divided by income. A measure of borrowing capacity that lenders watch; high DTI predicts default better than credit score alone.' },
  { term: 'Loan-to-Value', aliases: ['ltv', 'ratio prêt valeur'], category: 'personal', def: 'The mortgage size relative to the property value. Higher LTV means more risk for the lender and costlier insurance for the borrower.' },
  { term: 'HELOC', aliases: ['heloc', 'marge crédit hypothécaire'], category: 'personal', def: 'A revolving credit line secured by home equity. Cheap, flexible borrowing — but the family home is the collateral, so discipline matters.' },
  { term: 'Payday Loan', aliases: ['prêt sur gage', 'micro crédit'], category: 'personal', def: 'A tiny, very short-term loan at an annualized rate that can exceed 300%. A debt trap dressed as a lifeline — avoid unless truly desperate.' },
  { term: 'Grace Period', aliases: ['délai grâce', 'période franchise'], category: 'personal', def: 'The interest-free window on a credit card before the balance starts accruing. Exists only if you pay the previous statement in full.' },
  { term: 'Minimum Payment', aliases: ['paiement minimum'], category: 'personal', def: 'The smallest amount a card issuer will accept. Paying only this turns a small balance into years of compounding interest — the profit engine of card issuers.' },
  { term: 'Foreclosure', aliases: ['saisie immobilière', 'foreclosure'], category: 'personal', def: 'A lender repossessing and selling a home after missed mortgage payments. The loss of a home and a severe credit wound that lasts years.' },
  { term: 'Bankruptcy', aliases: ['faillite (particulier)', 'banqueroute'], category: 'personal', def: 'A legal process to discharge debts you cannot pay. A fresh start, but a long credit stain — and some debts (taxes, student loans) survive it.' },
  { term: 'Insolvency', aliases: ['insolvabilité'], category: 'personal', def: 'The state of debts exceeding assets, or inability to pay as they fall due. The trigger for bankruptcy or restructuring.' },
  { term: 'Pension', aliases: ['retraite (pension)', 'pension'], category: 'personal', def: 'Income paid in retirement, from a state scheme, an employer, or savings. The three pillars most countries combine — public, occupational, personal.' },
  { term: 'Roth IRA', aliases: ['roth ira', '401k', 'plan retraite us'], category: 'personal', def: 'A US retirement account funded with after-tax money, growing tax-free. The mirror of a traditional IRA, which is funded pre-tax and taxed on withdrawal.' },
  { term: 'SIPP', aliases: ['sipp', 'isa', 'plan retraite uk'], category: 'personal', def: 'A UK self-invested personal pension and ISA tax wrappers. The local vehicles for tax-advantaged long-term saving and investing.' },

  /* ---------------- ACCOUNTING (extended) ---------------- */
  { term: 'Current Ratio', aliases: ['ratio liquidité courante', 'current ratio'], category: 'accounting', def: 'Current assets divided by current liabilities — can the firm pay its near-term bills? Above 1 is comfortable; too high may mean idle cash.' },
  { term: 'Quick Ratio', aliases: ['quick ratio', 'ratio trésorerie'], category: 'accounting', def: 'Like current ratio but excludes inventory — a tougher liquidity test. If this is above 1, the firm can pay short-term debts without selling any stock.' },
  { term: 'Cash Ratio', aliases: ['ratio cash'], category: 'accounting', def: 'Cash divided by current liabilities — the strictest liquidity gauge. Most healthy firms score below 1, since holding that much cash is inefficient.' },
  { term: 'Inventory Turnover', aliases: ['rotation stocks', 'inventory turnover'], category: 'accounting', def: 'Cost of goods sold divided by inventory — how often stock is sold and replaced. High is efficient or possibly under-stocked; low risks obsolescence.' },
  { term: 'Days Sales Outstanding', aliases: ['délai encaissement', 'dso'], category: 'accounting', def: 'Average days to collect receivables. Rising DSO means customers pay slower — a quiet warning about sales quality or collection discipline.' },
  { term: 'Days Payable Outstanding', aliases: ['délai paiement', 'dpo'], category: 'accounting', def: 'Average days the firm takes to pay suppliers. Lengthening it is cheap financing, but strains supplier relationships if pushed too far.' },
  { term: 'Debt-to-Equity', aliases: ['dette fonds propres', 'd/e'], category: 'corporate', def: 'Total debt divided by equity — a leverage gauge. High means aggressive financing and higher risk; the right level varies by industry.' },
  { term: 'Interest Coverage', aliases: ['couverture intérêts'], category: 'corporate', def: 'Operating profit divided by interest. How many times the firm could pay interest from current earnings — below 2 is danger, below 1 is distress.' },
  { term: 'Tangible Book Value', aliases: ['valeur comptable tangible'], category: 'accounting', def: 'Book value minus goodwill and intangibles — the hard assets behind the shares. A conservative floor value, used for banks and asset-heavy firms.' },
  { term: 'Segment Reporting', aliases: ['reporting segmentaire'], category: 'accounting', def: 'Breaking results down by business line or geography. Reveals where a firm actually earns, and which segments are dragging or carrying the whole.' },
  { term: 'Audit Opinion', aliases: ['opinion audit', 'rapport audit'], category: 'accounting', def: 'The auditor conclusion on whether the statements fairly present the finances. "Unqualified" is clean; any qualifier is a serious red flag for investors.' },
  { term: 'Going Concern', aliases: ['continuité exploitation'], category: 'accounting', def: 'The assumption a firm will keep operating for the next year. A "going-concern" doubt from the auditor is a loud warning that survival is in question.' },
  { term: 'Provisions', aliases: ['provisions (compta)'], category: 'accounting', def: 'Charges set aside for likely but uncertain future losses (bad debts, lawsuits). A judgment call that can smooth or manipulate earnings — watch the trend.' },
  { term: 'Contingent Liability', aliases: ['passif éventuel'], category: 'accounting', def: 'A possible obligation depending on a future event (a lawsuit outcome). Disclosed in notes if material; recognized only when probable and measurable.' },
  { term: 'Revenue Recognition', aliases: ['comptabilisation revenu'], category: 'accounting', def: 'The rules for when revenue is booked — a frequent area of manipulation. New standards require revenue as the good or service is transferred to the customer.' },

  /* ---------------- MARKETS (extended) ---------------- */
  { term: 'Index Provider', aliases: ['calculateur indice', 'index provider'], category: 'markets', def: 'A firm that designs and maintains indexes (MSCI, FTSE, S&P). Their rules decide what index funds hold — quiet but immense power over trillions.' },
  { term: 'Index Reconstitution', aliases: ['reconstitution (indice)'], category: 'markets', def: 'The periodic rebalance of an index to its rules (size, free float). Forces funds to trade, creating predictable flows around the date.' },
  { term: 'Market-On-Close', aliases: ['moc', 'ordre clôture'], category: 'markets', def: 'An order to execute at the closing auction price. Used to match benchmarks; concentrates volume and volatility at the bell.' },
  { term: 'VWAP', aliases: ['vwap', 'prix moyen pondéré'], category: 'markets', def: 'Volume-Weighted Average Price — the average price weighted by volume over a period. The benchmark institutions measure their execution against.' },
  { term: 'TWAP', aliases: ['twap'], category: 'markets', def: 'Time-Weighted Average Price — slicing an order evenly over time to minimize market impact. Used when volume is hard to predict.' },
  { term: 'Block Trade', aliases: ['bloc (transaction)', 'block trade'], category: 'markets', def: 'A large privately-negotiated trade, often done upstairs or in a dark pool. Lets institutions move size without moving the public price.' },
  { term: 'Circuit Breaker', aliases: ['disjoncteur', 'circuit breaker'], category: 'markets', def: 'A temporary halt to trading after a sharp move. Gives markets a pause to breathe and reassess; whether it helps or just delays is debated.' },
  { term: 'Short Interest', aliases: ['positions short ouvertes', 'short interest'], category: 'markets', def: 'The total shares sold short and not yet covered. High and rising can signal bearish conviction — or a crowded short ripe for a squeeze.' },
  { term: 'Volume', aliases: ['volume (séance)'], category: 'markets', def: 'The number of shares or contracts traded in a period. Confirms or contradicts price moves — big breakouts on thin volume are suspect.' },
  { term: 'Turnover', aliases: ['rotation (volume)', 'turnover'], category: 'markets', def: 'The value of shares traded relative to market cap. A liquidity gauge for a whole market — high turnover usually means efficient, low-cost trading.' },
  { term: 'Advance-Decline Line', aliases: ['hausses baisses', 'advance decline'], category: 'markets', def: 'A running total of advancing minus declining stocks. Diverging from the index (new highs on narrowing breadth) is a classic top warning.' },
  { term: 'Market Breadth', aliases: ['largeur marché', 'breadth'], category: 'markets', def: 'How many stocks participate in a move. Broad participation confirms a rally; narrow leadership (a few names carrying the index) is fragile.' },

  /* ---------------- RISK (extended) ---------------- */
  { term: 'Scenario Analysis', aliases: ['analyse scénario'], category: 'risk', def: 'Evaluating outcomes under specific hypothetical stories (oil doubles, rates spike). Complements statistics by asking what would happen, not just what usually does.' },
  { term: 'Monte Carlo Simulation', aliases: ['monte carlo', 'simulation aléatoire'], category: 'risk', def: 'Running thousands of random trials to map the distribution of outcomes. Reveals the full range and tail, not just an average — central to modern risk modeling.' },
  { term: 'Copula', aliases: ['copule (dépendance)'], category: 'risk', def: 'A function modeling how variables depend on each other, separate from their individual distributions. The "wrong copula" assumption helped sink CDO models in 2008.' },
  { term: 'Historical VaR', aliases: ['var historique'], category: 'risk', def: 'Value at Risk estimated from the actual past distribution of returns. Simple and assumption-light, but anchored to history that may not include the next crisis.' },
  { term: 'Parametric VaR', aliases: ['var paramétrique'], category: 'risk', def: 'Value at Risk estimated from a fitted distribution (often normal). Clean and fast, but underestimates fat tails — the dangerous events it should be catching.' },
  { term: 'Backtesting (Risk)', aliases: ['rétro test risque', 'backtesting risque'], category: 'risk', def: 'Checking whether predicted losses would have matched actuals in history. Required for bank models; failures force higher capital under the rules.' },
  { term: 'Model Risk', aliases: ['risque modèle'], category: 'risk', def: 'The risk a model is wrong — wrong inputs, wrong assumptions, or misuse. The failure mode behind most quant blow-ups; models are tools, not truths.' },
  { term: 'Operational Risk', aliases: ['risque opérationnel'], category: 'risk', def: 'The risk of loss from failed processes, people, or systems — a fraud, a rogue trade, an IT outage. Hard to model, often the largest real loss source.' },
  { term: 'Liquidity Risk', aliases: ['risque liquidité'], category: 'risk', conceptId: 'liquidity', def: 'The risk of being unable to sell an asset without a steep price cut. Dries up exactly when needed most — the silent killer in every crisis.' },
  { term: 'Concentration Risk', aliases: ['risque concentration'], category: 'risk', def: 'Risk from too much exposure to one name, sector, country, or factor. The opposite of diversification; the common thread in many blow-ups.' },
  { term: 'Settlement Risk', aliases: ['risque règlement'], category: 'risk', def: 'The risk that one party pays and the other does not deliver — the reason for clearing and delivery-versus-payment. Peak at the moment of exchange.' },
  { term: 'Model Validation', aliases: ['validation modèle'], category: 'risk', def: 'An independent review that a model is fit for purpose. Regulators require it for banks; the line between a useful model and a weapon of loss.' },
  { term: 'Risk Appetite', aliases: ['appétit risque'], category: 'risk', def: 'The level of risk an institution is willing to accept to hit its goals. Set at the top, cascaded into limits — the bridge from strategy to daily risk-taking.' },
  { term: 'Key Risk Indicator', aliases: ['kri', 'indicateur clé risque'], category: 'risk', def: 'A metric tracked as an early warning of rising risk (limit use, errors, exposures). The dashboard that tells a firm its risk is building before it breaks.' },

  /* ---------------- FINTECH (extended) ---------------- */
  { term: 'Tokenization (assets)', aliases: ['tokenisation actifs', 'jeton actifs'], category: 'fintech', def: 'Representing real assets (bonds, property, funds) as blockchain tokens. Promises faster settlement and fractional ownership — still early in legal and custody terms.' },
  { term: 'Web3', aliases: ['web3', 'web 3'], category: 'fintech', def: 'A vision of a decentralized internet built on blockchains and tokens. Hyped and contested; the financial layer is the most concrete part so far.' },
  { term: 'Layer 2', aliases: ['layer 2', 'solution couche 2'], category: 'fintech', def: 'A network built on top of a blockchain to handle transactions cheaply, settling to the base layer. The scalability answer for Ethereum.' },
  { term: 'Gas Fee', aliases: ['frais gas', 'frais réseau'], category: 'fintech', def: 'The fee paid to process a transaction on a blockchain. Spikes when the network is busy — the cost that decides which uses are viable.' },
  { term: 'Slippage (DeFi)', aliases: ['slippage defi'], category: 'fintech', def: 'The price change while a DeFi trade executes, due to pool depth. Large trades move automated pools against themselves — the cost of size without order books.' },
  { term: 'Impermanent Loss', aliases: ['perte impermanente'], category: 'fintech', def: 'The gap between holding assets and providing them as DeFi liquidity. Earns fees but loses when prices diverge — can outweigh the fees in volatile pairs.' },
  { term: 'Liquidity Pool', aliases: ['pool liquidité defi'], category: 'fintech', def: 'Funds locked in a smart contract that traders swap against, priced by an algorithm. The DeFi substitute for an order book, with no counterparty but the code.' },
  { term: 'Oracle', aliases: ['oracle (blockchain)'], category: 'fintech', def: 'A service feeding real-world data (prices, rates) to a blockchain. The bridge between on-chain contracts and off-chain reality — and a juicy attack target.' },
  { term: 'Bridge', aliases: ['pont (blockchain)'], category: 'fintech', def: 'A protocol moving assets between blockchains. Convenient and necessary, but historically the most-hacked part of crypto — a concentration of risk.' },
  { term: 'Airdrop', aliases: ['airdrop', 'distribution jetons'], category: 'fintech', def: 'Free tokens distributed to users, often to bootstrap adoption. A marketing tool and a reward — sometimes worth real money, often not.' },
  { term: 'Staking', aliases: ['staking', 'mise en jeu (pos)'], category: 'fintech', def: 'Locking tokens to help secure a proof-of-stake network and earn rewards. The crypto equivalent of interest — paid for participation, not for lending.' },
  { term: 'Custody (crypto)', aliases: ['garde crypto', 'custody crypto'], category: 'fintech', def: 'Secure storage of crypto keys. The divide between holding your own keys (risk of loss) and using an institution (risk of the institution).' },
  { term: 'KYT', aliases: ['kyt', 'connaissance transactions'], category: 'fintech', def: 'Know-Your-Transaction — tracing crypto flows to detect illicit activity. The blockchain answer to AML, since every transfer is on a public ledger.' },
  { term: 'Embedded Finance', aliases: ['finance intégrée', 'embedded finance'], category: 'fintech', def: 'Financial services built into non-financial products — insurance at checkout, lending in a shopping app. Finance fading into the background of other software.' },
  { term: 'BNPL', aliases: ['bnpl', 'paiement échelonné', 'buy now pay later'], category: 'fintech', def: 'Buy Now Pay Later — interest-free installments at checkout. Convenient for buyers, profitable for lenders from merchant fees, and a rising debt concern.' },

  /* ---------------- INVESTING (extended) ---------------- */
  { term: 'Tracking Portfolio', aliases: ['portefeuille de réplication'], category: 'investing', def: 'A portfolio built to mimic an index or benchmark return. The art of index funds — full replication or sampling, balancing cost against tracking error.' },
  { term: 'Smart Beta', aliases: ['smart beta', 'bêta intelligent'], category: 'investing', def: 'Rules-based funds that tilt toward rewarded factors (value, momentum, low-vol) rather than market cap. A middle ground between active and pure indexing.' },
  { term: 'Direct Indexing', aliases: ['indexation directe'], category: 'investing', def: 'Owning the individual stocks of an index, not a fund. Enables tax-loss harvesting and customization, at the cost of complexity — the frontier of passive.' },
  { term: 'Separately Managed Account', aliases: ['sma', 'compte géré séparé'], category: 'investing', def: 'A portfolio managed for one investor, not pooled. Direct ownership, customization, and tax control, at higher minimums than a fund.' },
  { term: 'Model Portfolio', aliases: ['portefeuille modèle'], category: 'investing', def: 'A ready-made asset mix advisors can apply to client accounts. Standardizes advice at scale; the delivery layer of modern wealth management.' },
  { term: 'Glide Path', aliases: ['trajectoire (target date)', 'glide path'], category: 'investing', def: 'The planned shift of a target-date fund from growth to safe assets as the retirement date approaches. Automatic de-risking by calendar.' },
  { term: 'Sequence-of-Returns Risk', aliases: ['risque séquence rendements'], category: 'investing', def: 'The danger that bad years early in retirement wreck a portfolio more than the same years later. Withdrawals from a falling portfolio are ruinous — the case for de-risking near retirement.' },
  { term: 'Safe Withdrawal Rate', aliases: ['taux retrait sécuritaire', 'swr'], category: 'personal', def: 'The share of a portfolio one can draw yearly with low risk of running out. The 4% rule is the famous estimate, debated and stress-tested across history.' },

  /* ---------------- ECONOMICS (extended) ---------------- */
  { term: 'Deficit Spending', aliases: ['dépense déficitaire'], category: 'economics', def: 'A government spending more than it collects, borrowing the gap. Stimulative in a slump, inflationary if the economy is already at capacity.' },
  { term: 'Crowding Out', aliases: ['effet éviction'], category: 'economics', def: 'Government borrowing pushing up rates and reducing private investment. The classic argument against large deficits in a near-full-employment economy.' },
  { term: 'Multiplier Effect', aliases: ['effet multiplicateur'], category: 'economics', def: 'How a unit of spending generates more than a unit of output, as money circulates. Larger when there is slack; smaller when the economy is capacity-constrained.' },
  { term: 'Velocity of Money', aliases: ['vitesse circulation monnaie'], category: 'economics', def: 'How often a unit of currency changes hands in a period. Falling velocity can offset rising money supply, keeping inflation tame — as seen post-2008.' },
  { term: 'Hawkish', aliases: ['hawkish', 'faucon (banque centrale)'], category: 'economics', def: 'A central-bank stance biased toward fighting inflation, even at the cost of growth. Hawks favor higher rates; doves favor lower.' },
  { term: 'Dovish', aliases: ['dovish', 'colombe (banque centrale)'], category: 'economics', def: 'A central-bank stance biased toward growth and employment, tolerant of some inflation. Doves favor lower rates; hawks favor higher.' },
  { term: 'Real Interest Rate', aliases: ['taux réel'], category: 'economics', conceptId: 'interest-rate', def: 'The interest rate minus inflation — the true cost of borrowing. Negative real rates effectively pay borrowers to borrow, fueling leverage.' },
  { term: 'Potential Output', aliases: ['production potentielle'], category: 'economics', def: 'What an economy can produce at full employment without inflation. The sustainable ceiling; output above it overheats, below it leaves resources idle.' },
  { term: 'Trend Growth', aliases: ['croissance tendancielle'], category: 'economics', def: 'The long-run average pace of expansion, set by demographics and productivity. What policy cannot change in the short run, only the cycle around it.' },
];

/* ---------------- Search helpers ---------------- */

// Lowercase a string for matching.
const norm = (s) => (s || '').toString().toLowerCase().trim();

// Search the glossary. Matches if every space-separated token of the query
// appears in the term, an alias, or the definition (token-level AND match).
// Exact alias/term hits are ranked first.
export const searchGlossary = (query) => {
  const q = norm(query);
  if (!q) return [];
  const tokens = q.split(/\s+/).filter(Boolean);

  const scored = glossary
    .map((entry) => {
      const termLow = norm(entry.term);
      const aliasesLow = (entry.aliases || []).map(norm);
      const defLow = norm(entry.def);
      const haystacks = [termLow, ...aliasesLow];

      // Exact alias/term match → highest rank
      const exact = haystacks.some((h) => h === q || h === q + 's' || q === h + 's' || h === q + 'e');
      // Starts-with match
      const starts = !exact && haystacks.some((h) => h.startsWith(q) || q.startsWith(h));
      // Token match: every query token present somewhere in term/alias/def
      const tokenMatch = tokens.every(
        (t) => termLow.includes(t) || aliasesLow.some((a) => a.includes(t)) || defLow.includes(t)
      );

      let rank = -1;
      if (exact) rank = 3;
      else if (starts) rank = 2;
      else if (tokenMatch) rank = 1;
      if (rank < 0) return null;

      return { entry, rank };
    })
    .filter(Boolean);

  scored.sort((a, b) => b.rank - a.rank);
  return scored.map((s) => s.entry);
};

// Look up a single glossary entry by matching term or alias (case-insensitive).
export const findGlossaryEntry = (term) => {
  const t = norm(term);
  return glossary.find(
    (e) => norm(e.term) === t || (e.aliases || []).some((a) => norm(a) === t)
  ) || null;
};